// FJ-256: forjar lock — generate lock file without applying
fn cmd_lock(
    file: &Path,
    state_dir: &Path,
    env_file: Option<&Path>,
    workspace: Option<&str>,
    verify: bool,
    json: bool,
) -> Result<(), String> {
    use crate::core::planner::hash_desired_state;
    use crate::tripwire::eventlog::now_iso8601;

    let mut config = parse_and_validate(file)?;
    if let Some(path) = env_file {
        load_env_params(&mut config, path)?;
    }
    inject_workspace_param(&mut config, workspace);
    resolver::resolve_data_sources(&mut config)?;

    let execution_order = resolver::build_execution_order(&config)?;

    // Group resources by machine
    let mut machine_resources: indexmap::IndexMap<String, Vec<(String, &types::Resource)>> =
        indexmap::IndexMap::new();
    for res_id in &execution_order {
        if let Some(resource) = config.resources.get(res_id) {
            let machines = match &resource.machine {
                types::MachineTarget::Single(m) => vec![m.clone()],
                types::MachineTarget::Multiple(ms) => ms.clone(),
            };
            for m in machines {
                machine_resources
                    .entry(m)
                    .or_default()
                    .push((res_id.clone(), resource));
            }
        }
    }

    let mut mismatches: Vec<String> = Vec::new();
    let mut total_resources = 0usize;
    let mut total_machines = 0usize;

    for (machine_name, resources) in &machine_resources {
        let hostname = config
            .machines
            .get(machine_name)
            .map(|m| m.hostname.as_str())
            .unwrap_or(machine_name);

        let mut lock = state::new_lock(machine_name, hostname);

        for (res_id, resource) in resources {
            let hash = hash_desired_state(resource);
            lock.resources.insert(
                res_id.clone(),
                types::ResourceLock {
                    resource_type: resource.resource_type.clone(),
                    status: types::ResourceStatus::Unknown,
                    applied_at: None,
                    duration_seconds: None,
                    hash: hash.clone(),
                    details: std::collections::HashMap::new(),
                },
            );
            total_resources += 1;
        }

        if verify {
            // Compare against existing lock
            let existing = state::load_lock(state_dir, machine_name)?;
            match existing {
                None => {
                    mismatches.push(format!("{}: no existing lock file", machine_name));
                }
                Some(existing_lock) => {
                    for (res_id, new_res_lock) in &lock.resources {
                        match existing_lock.resources.get(res_id) {
                            None => {
                                mismatches
                                    .push(format!("{}:{}: not in lock file", machine_name, res_id));
                            }
                            Some(existing_res) => {
                                if existing_res.hash != new_res_lock.hash {
                                    mismatches.push(format!(
                                        "{}:{}: hash mismatch (lock={}, config={})",
                                        machine_name,
                                        res_id,
                                        &existing_res.hash[..15.min(existing_res.hash.len())],
                                        &new_res_lock.hash[..15.min(new_res_lock.hash.len())],
                                    ));
                                }
                            }
                        }
                    }
                    // Check for resources in lock that are no longer in config
                    for res_id in existing_lock.resources.keys() {
                        if !lock.resources.contains_key(res_id) {
                            mismatches.push(format!(
                                "{}:{}: in lock but not in config",
                                machine_name, res_id
                            ));
                        }
                    }
                }
            }
        } else {
            // Write lock file
            state::save_lock(state_dir, &lock)?;
        }

        total_machines += 1;
    }

    if verify {
        if json {
            let result = serde_json::json!({
                "verified": mismatches.is_empty(),
                "machines": total_machines,
                "resources": total_resources,
                "mismatches": mismatches,
            });
            println!(
                "{}",
                serde_json::to_string_pretty(&result).map_err(|e| format!("JSON error: {}", e))?
            );
        } else if mismatches.is_empty() {
            println!(
                "Lock verified: {} machines, {} resources — all hashes match",
                total_machines, total_resources
            );
        } else {
            println!("Lock verification FAILED:");
            for m in &mismatches {
                println!("  - {}", m);
            }
        }
        if !mismatches.is_empty() {
            std::process::exit(1);
        }
    } else {
        // Also update global lock
        let machine_results: Vec<(String, usize, usize, usize)> = machine_resources
            .iter()
            .map(|(name, resources)| (name.clone(), resources.len(), 0, 0))
            .collect();
        state::update_global_lock(state_dir, &config.name, &machine_results)?;

        if json {
            let result = serde_json::json!({
                "locked": true,
                "machines": total_machines,
                "resources": total_resources,
                "state_dir": state_dir.display().to_string(),
                "generated_at": now_iso8601(),
            });
            println!(
                "{}",
                serde_json::to_string_pretty(&result).map_err(|e| format!("JSON error: {}", e))?
            );
        } else {
            println!(
                "Locked: {} machines, {} resources → {}",
                total_machines,
                total_resources,
                state_dir.display()
            );
        }
    }

    Ok(())
}

// FJ-260: forjar snapshot — named state checkpoints

fn snapshots_dir(state_dir: &Path) -> PathBuf {
    state_dir.join("snapshots")
}

fn cmd_snapshot_save(name: &str, state_dir: &Path) -> Result<(), String> {
    if !state_dir.exists() {
        return Err(format!(
            "state directory does not exist: {}",
            state_dir.display()
        ));
    }
    let snap_dir = snapshots_dir(state_dir).join(name);
    if snap_dir.exists() {
        return Err(format!("snapshot '{}' already exists", name));
    }
    std::fs::create_dir_all(&snap_dir).map_err(|e| format!("cannot create snapshot dir: {}", e))?;

    // Copy all files/dirs in state_dir except "snapshots" itself
    copy_dir_recursive(state_dir, &snap_dir, "snapshots")?;

    // Write metadata
    let meta = format!(
        "created_at: \"{}\"\nname: \"{}\"\n",
        crate::tripwire::eventlog::now_iso8601(),
        name
    );
    std::fs::write(snap_dir.join(".snapshot.yaml"), meta)
        .map_err(|e| format!("cannot write snapshot metadata: {}", e))?;

    println!("Snapshot saved: {}", name);
    Ok(())
}

fn cmd_snapshot_list(state_dir: &Path, json: bool) -> Result<(), String> {
    let snap_base = snapshots_dir(state_dir);
    if !snap_base.exists() {
        if json {
            println!("[]");
        } else {
            println!("No snapshots.");
        }
        return Ok(());
    }

    let mut snapshots: Vec<(String, String)> = Vec::new();
    let entries =
        std::fs::read_dir(&snap_base).map_err(|e| format!("cannot read snapshots dir: {}", e))?;
    for entry in entries.flatten() {
        if entry.file_type().map(|t| t.is_dir()).unwrap_or(false) {
            let name = entry.file_name().to_string_lossy().to_string();
            let meta_path = entry.path().join(".snapshot.yaml");
            let created = if meta_path.exists() {
                std::fs::read_to_string(&meta_path)
                    .ok()
                    .and_then(|c| {
                        c.lines().find(|l| l.starts_with("created_at:")).map(|l| {
                            l.trim_start_matches("created_at:")
                                .trim()
                                .trim_matches('"')
                                .to_string()
                        })
                    })
                    .unwrap_or_else(|| "unknown".to_string())
            } else {
                "unknown".to_string()
            };
            snapshots.push((name, created));
        }
    }
    snapshots.sort_by(|a, b| a.0.cmp(&b.0));

    if json {
        let items: Vec<serde_json::Value> = snapshots
            .iter()
            .map(|(n, c)| serde_json::json!({"name": n, "created_at": c}))
            .collect();
        println!(
            "{}",
            serde_json::to_string_pretty(&items).map_err(|e| format!("JSON error: {}", e))?
        );
    } else if snapshots.is_empty() {
        println!("No snapshots.");
    } else {
        for (name, created) in &snapshots {
            println!("  {} ({})", name, created);
        }
    }
    Ok(())
}

fn cmd_snapshot_restore(name: &str, state_dir: &Path, yes: bool) -> Result<(), String> {
    let snap_dir = snapshots_dir(state_dir).join(name);
    if !snap_dir.exists() {
        return Err(format!("snapshot '{}' does not exist", name));
    }
    if !yes {
        return Err("Restore will overwrite current state. Use --yes to confirm.".to_string());
    }

    // Remove current state (except snapshots dir)
    let entries =
        std::fs::read_dir(state_dir).map_err(|e| format!("cannot read state dir: {}", e))?;
    for entry in entries.flatten() {
        let name_os = entry.file_name();
        if name_os.to_string_lossy() == "snapshots" {
            continue;
        }
        let path = entry.path();
        if path.is_dir() {
            std::fs::remove_dir_all(&path)
                .map_err(|e| format!("cannot remove {}: {}", path.display(), e))?;
        } else {
            std::fs::remove_file(&path)
                .map_err(|e| format!("cannot remove {}: {}", path.display(), e))?;
        }
    }

    // Copy snapshot back (excluding .snapshot.yaml metadata)
    copy_dir_recursive(&snap_dir, state_dir, ".snapshot.yaml")?;

    println!("Restored snapshot: {}", name);
    Ok(())
}

fn cmd_snapshot_delete(name: &str, state_dir: &Path) -> Result<(), String> {
    let snap_dir = snapshots_dir(state_dir).join(name);
    if !snap_dir.exists() {
        return Err(format!("snapshot '{}' does not exist", name));
    }
    std::fs::remove_dir_all(&snap_dir).map_err(|e| format!("cannot delete snapshot: {}", e))?;
    println!("Deleted snapshot: {}", name);
    Ok(())
}

/// Recursively copy a directory, skipping entries whose name matches `skip`.
fn copy_dir_recursive(src: &Path, dst: &Path, skip: &str) -> Result<(), String> {
    let entries =
        std::fs::read_dir(src).map_err(|e| format!("cannot read {}: {}", src.display(), e))?;
    for entry in entries.flatten() {
        let name = entry.file_name();
        if name.to_string_lossy() == skip {
            continue;
        }
        let src_path = entry.path();
        let dst_path = dst.join(&name);
        if src_path.is_dir() {
            std::fs::create_dir_all(&dst_path)
                .map_err(|e| format!("cannot create {}: {}", dst_path.display(), e))?;
            copy_dir_recursive(&src_path, &dst_path, "")?;
        } else {
            std::fs::copy(&src_path, &dst_path).map_err(|e| {
                format!(
                    "cannot copy {} → {}: {}",
                    src_path.display(),
                    dst_path.display(),
                    e
                )
            })?;
        }
    }
    Ok(())
}

// FJ-251: forjar doctor — pre-flight system checker
fn cmd_doctor(file: Option<&Path>, json: bool, fix: bool) -> Result<(), String> {
    use std::process::Command;

    #[derive(Debug)]
    struct Check {
        name: String,
        status: CheckStatus,
        detail: String,
    }

    #[derive(Debug, PartialEq)]
    enum CheckStatus {
        Pass,
        Warn,
        Fail,
    }

    let mut checks: Vec<Check> = Vec::new();

    // 1. bash >= 4.0
    match Command::new("bash").arg("--version").output() {
        Ok(out) => {
            let ver = String::from_utf8_lossy(&out.stdout);
            // Extract version number from "GNU bash, version X.Y.Z..."
            let version_str = ver.lines().next().unwrap_or("").to_string();
            if let Some(pos) = version_str.find("version ") {
                let after = &version_str[pos + 8..];
                let major: u32 = after
                    .chars()
                    .take_while(|c| c.is_ascii_digit())
                    .collect::<String>()
                    .parse()
                    .unwrap_or(0);
                if major >= 4 {
                    checks.push(Check {
                        name: "bash".to_string(),
                        status: CheckStatus::Pass,
                        detail: format!(
                            "bash {}",
                            &after[..after
                                .find(|c: char| c.is_whitespace() || c == '(')
                                .unwrap_or(after.len())]
                        ),
                    });
                } else {
                    checks.push(Check {
                        name: "bash".to_string(),
                        status: CheckStatus::Fail,
                        detail: format!("bash {} (need >= 4.0)", major),
                    });
                }
            } else {
                checks.push(Check {
                    name: "bash".to_string(),
                    status: CheckStatus::Warn,
                    detail: "cannot parse bash version".to_string(),
                });
            }
        }
        Err(_) => {
            checks.push(Check {
                name: "bash".to_string(),
                status: CheckStatus::Fail,
                detail: "bash not found in PATH".to_string(),
            });
        }
    }

    // 2. Parse config if provided to determine what else to check
    let config: Option<types::ForjarConfig> = if let Some(f) = file {
        match parser::parse_and_validate(f) {
            Ok(c) => Some(c),
            Err(e) => {
                checks.push(Check {
                    name: "config".to_string(),
                    status: CheckStatus::Fail,
                    detail: format!("parse error: {}", e),
                });
                None
            }
        }
    } else {
        None
    };

    let has_ssh_machines = config
        .as_ref()
        .map(|c| {
            c.machines.values().any(|m| {
                m.transport.as_deref() != Some("container")
                    && m.addr != "127.0.0.1"
                    && m.addr != "localhost"
                    && m.addr != "container"
            })
        })
        .unwrap_or(false);

    let has_container_machines = config
        .as_ref()
        .map(|c| {
            c.machines
                .values()
                .any(|m| m.transport.as_deref() == Some("container") || m.addr == "container")
        })
        .unwrap_or(false);

    let has_enc_markers = file
        .and_then(|f| std::fs::read_to_string(f).ok())
        .map(|content| secrets::has_encrypted_markers(&content))
        .unwrap_or(false);

    // 3. ssh (only if SSH machines configured)
    if has_ssh_machines {
        match Command::new("ssh").arg("-V").output() {
            Ok(out) => {
                let ver = String::from_utf8_lossy(&out.stderr);
                let version_line = ver.lines().next().unwrap_or("ssh available").to_string();
                checks.push(Check {
                    name: "ssh".to_string(),
                    status: CheckStatus::Pass,
                    detail: version_line,
                });
            }
            Err(_) => {
                checks.push(Check {
                    name: "ssh".to_string(),
                    status: CheckStatus::Fail,
                    detail: "ssh not found (needed for remote machines)".to_string(),
                });
            }
        }
    }

    // 4. docker/podman (only if container machines configured)
    if has_container_machines {
        let runtime = config
            .as_ref()
            .and_then(|c| {
                c.machines
                    .values()
                    .find_map(|m| m.container.as_ref().map(|ct| ct.runtime.clone()))
            })
            .unwrap_or_else(|| "docker".to_string());

        match Command::new(&runtime).arg("--version").output() {
            Ok(out) => {
                let ver = String::from_utf8_lossy(&out.stdout);
                let version_line = ver.lines().next().unwrap_or(&runtime).trim().to_string();
                checks.push(Check {
                    name: runtime.clone(),
                    status: CheckStatus::Pass,
                    detail: version_line,
                });
            }
            Err(_) => {
                checks.push(Check {
                    name: runtime.clone(),
                    status: CheckStatus::Fail,
                    detail: format!("{} not found (needed for container machines)", runtime),
                });
            }
        }
    }

    // 5. age identity (only if ENC markers present)
    if has_enc_markers {
        match secrets::load_identities(None) {
            Ok(ids) if !ids.is_empty() => {
                checks.push(Check {
                    name: "age".to_string(),
                    status: CheckStatus::Pass,
                    detail: format!("{} identity loaded", ids.len()),
                });
            }
            Ok(_) => {
                checks.push(Check {
                    name: "age".to_string(),
                    status: CheckStatus::Fail,
                    detail: "no age identity (set FORJAR_AGE_KEY or use --identity)".to_string(),
                });
            }
            Err(e) => {
                checks.push(Check {
                    name: "age".to_string(),
                    status: CheckStatus::Fail,
                    detail: format!("age identity error: {}", e),
                });
            }
        }
    }

    // 6. state dir writable
    let state_dir = Path::new("state");
    if state_dir.exists() {
        let test_path = state_dir.join(".doctor-probe");
        match std::fs::write(&test_path, "probe") {
            Ok(()) => {
                let _ = std::fs::remove_file(&test_path);
                checks.push(Check {
                    name: "state-dir".to_string(),
                    status: CheckStatus::Pass,
                    detail: format!("{} writable", state_dir.display()),
                });
            }
            Err(e) => {
                checks.push(Check {
                    name: "state-dir".to_string(),
                    status: CheckStatus::Fail,
                    detail: format!("{} not writable: {}", state_dir.display(), e),
                });
            }
        }
    } else if fix {
        // FJ-287: --fix creates missing state dir
        match std::fs::create_dir_all(state_dir) {
            Ok(()) => {
                checks.push(Check {
                    name: "state-dir".to_string(),
                    status: CheckStatus::Pass,
                    detail: format!("{} created (--fix)", state_dir.display()),
                });
            }
            Err(e) => {
                checks.push(Check {
                    name: "state-dir".to_string(),
                    status: CheckStatus::Fail,
                    detail: format!("cannot create {}: {}", state_dir.display(), e),
                });
            }
        }
    } else {
        checks.push(Check {
            name: "state-dir".to_string(),
            status: CheckStatus::Warn,
            detail: format!(
                "{} does not exist (will be created on apply)",
                state_dir.display()
            ),
        });
    }

    // FJ-287: Check for stale lock files
    if state_dir.exists() {
        let lock_path = state_dir.join(".forjar.lock");
        if lock_path.exists() {
            if fix {
                match std::fs::remove_file(&lock_path) {
                    Ok(()) => {
                        checks.push(Check {
                            name: "lock".to_string(),
                            status: CheckStatus::Pass,
                            detail: "stale lock removed (--fix)".to_string(),
                        });
                    }
                    Err(e) => {
                        checks.push(Check {
                            name: "lock".to_string(),
                            status: CheckStatus::Fail,
                            detail: format!("cannot remove lock: {}", e),
                        });
                    }
                }
            } else {
                checks.push(Check {
                    name: "lock".to_string(),
                    status: CheckStatus::Warn,
                    detail: "stale lock file exists (use --fix to remove)".to_string(),
                });
            }
        }
    }

    // 7. git repo clean
    match Command::new("git").args(["status", "--porcelain"]).output() {
        Ok(out) if out.status.success() => {
            let output = String::from_utf8_lossy(&out.stdout);
            if output.trim().is_empty() {
                checks.push(Check {
                    name: "git".to_string(),
                    status: CheckStatus::Pass,
                    detail: "working tree clean".to_string(),
                });
            } else {
                let line_count = output.lines().count();
                checks.push(Check {
                    name: "git".to_string(),
                    status: CheckStatus::Warn,
                    detail: format!("{} uncommitted changes", line_count),
                });
            }
        }
        Ok(_) => {
            checks.push(Check {
                name: "git".to_string(),
                status: CheckStatus::Warn,
                detail: "not a git repository".to_string(),
            });
        }
        Err(_) => {
            checks.push(Check {
                name: "git".to_string(),
                status: CheckStatus::Warn,
                detail: "git not found in PATH".to_string(),
            });
        }
    }

    // Output
    if json {
        println!("[");
        for (i, c) in checks.iter().enumerate() {
            let status_str = match c.status {
                CheckStatus::Pass => "pass",
                CheckStatus::Warn => "warn",
                CheckStatus::Fail => "fail",
            };
            let comma = if i + 1 < checks.len() { "," } else { "" };
            println!(
                "  {{\"name\":\"{}\",\"status\":\"{}\",\"detail\":\"{}\"}}{}",
                c.name,
                status_str,
                c.detail.replace('\"', "\\\""),
                comma
            );
        }
        println!("]");
    } else {
        for c in &checks {
            let icon = match c.status {
                CheckStatus::Pass => "pass",
                CheckStatus::Warn => "warn",
                CheckStatus::Fail => "FAIL",
            };
            println!("[{:>4}] {}: {}", icon, c.name, c.detail);
        }

        let pass_count = checks
            .iter()
            .filter(|c| c.status == CheckStatus::Pass)
            .count();
        let warn_count = checks
            .iter()
            .filter(|c| c.status == CheckStatus::Warn)
            .count();
        let fail_count = checks
            .iter()
            .filter(|c| c.status == CheckStatus::Fail)
            .count();
        println!(
            "\n{} checks: {} pass, {} warn, {} fail",
            checks.len(),
            pass_count,
            warn_count,
            fail_count
        );
    }

    let has_failures = checks.iter().any(|c| c.status == CheckStatus::Fail);
    if has_failures {
        Err("doctor found failures".to_string())
    } else {
        Ok(())
    }
}

/// FJ-326: List all machines with connection status.
fn cmd_inventory(file: &Path, json: bool) -> Result<(), String> {
    let config = parse_and_validate(file)?;

    let mut results: Vec<serde_json::Value> = Vec::new();

    for (name, machine) in &config.machines {
        let is_local = machine.addr == "127.0.0.1" || machine.addr == "localhost";
        let is_container =
            machine.addr == "container" || machine.transport.as_deref() == Some("container");

        let (status, transport_type) = if is_local {
            ("reachable".to_string(), "local")
        } else if is_container {
            ("container".to_string(), "container")
        } else {
            // Try SSH connection test: ssh -o BatchMode=yes -o ConnectTimeout=5
            let user_host = format!("{}@{}", machine.user, machine.addr);
            let mut ssh_args = vec!["-o", "BatchMode=yes", "-o", "ConnectTimeout=5"];
            if let Some(ref key) = machine.ssh_key {
                ssh_args.push("-i");
                ssh_args.push(key);
            }
            ssh_args.push(&user_host);
            ssh_args.push("echo");
            ssh_args.push("ok");
            let result = std::process::Command::new("ssh")
                .args(&ssh_args)
                .stdout(std::process::Stdio::null())
                .stderr(std::process::Stdio::null())
                .status();
            match result {
                Ok(s) if s.success() => ("reachable".to_string(), "ssh"),
                _ => ("unreachable".to_string(), "ssh"),
            }
        };

        let resource_count = config
            .resources
            .values()
            .filter(|r| match &r.machine {
                types::MachineTarget::Single(m) => m == name,
                types::MachineTarget::Multiple(ms) => ms.contains(&name.to_string()),
            })
            .count();

        if json {
            results.push(serde_json::json!({
                "name": name,
                "hostname": machine.hostname,
                "addr": machine.addr,
                "user": machine.user,
                "arch": machine.arch,
                "transport": transport_type,
                "status": status,
                "roles": machine.roles,
                "resources": resource_count,
            }));
        } else {
            let status_icon = match status.as_str() {
                "reachable" => green("●"),
                "container" => dim("◆"),
                _ => red("✗"),
            };
            println!(
                "  {} {} ({}) [{}] — {} via {} ({} resources)",
                status_icon,
                name,
                machine.hostname,
                machine.addr,
                status,
                transport_type,
                resource_count,
            );
        }
    }

    if json {
        println!(
            "{}",
            serde_json::to_string_pretty(&results).unwrap_or_default()
        );
    } else {
        println!("\n{} machines in inventory", config.machines.len());
    }

    Ok(())
}

/// FJ-327: Re-run only previously failed resources.
fn cmd_retry_failed(
    file: &Path,
    state_dir: &Path,
    param_overrides: &[String],
    timeout: Option<u64>,
) -> Result<(), String> {
    let config = parse_and_validate(file)?;

    // Scan event logs for the most recent ResourceFailed events per machine
    let mut failed_resources: Vec<(String, String)> = Vec::new(); // (machine, resource)

    for (name, _machine) in &config.machines {
        let log_path = eventlog::event_log_path(state_dir, name);
        if !log_path.exists() {
            continue;
        }
        let content = std::fs::read_to_string(&log_path)
            .map_err(|e| format!("cannot read {}: {}", log_path.display(), e))?;

        // Find the last ApplyCompleted to mark the boundary, then collect
        // ResourceFailed events after the last ApplyCompleted
        let mut last_apply_line = 0usize;
        let lines: Vec<&str> = content.lines().collect();
        for (i, line) in lines.iter().enumerate() {
            if line.contains("ApplyCompleted") {
                last_apply_line = i;
            }
        }

        // Collect ResourceFailed events from the last apply run
        // We scan backwards from the last ApplyCompleted to find ResourceFailed in that run
        for line in &lines[..=last_apply_line] {
            if let Ok(event) = serde_json::from_str::<types::TimestampedEvent>(line) {
                if let types::ProvenanceEvent::ResourceFailed {
                    ref machine,
                    ref resource,
                    ..
                } = event.event
                {
                    // Check if this is from the most recent run (same machine)
                    if machine == name {
                        failed_resources.push((name.clone(), resource.clone()));
                    }
                }
            }
        }
    }

    if failed_resources.is_empty() {
        println!("No failed resources found in event logs. Nothing to retry.");
        return Ok(());
    }

    println!("Retrying {} failed resource(s):", failed_resources.len());
    for (machine, resource) in &failed_resources {
        println!("  {} → {}", machine, resource);
    }
    println!();

    // Apply each failed resource individually
    for (machine, resource) in &failed_resources {
        println!("Retrying {} on {}...", resource, machine);
        cmd_apply(
            file,
            state_dir,
            Some(machine),
            Some(resource),
            None,  // tag_filter
            None,  // group_filter
            true,  // force — re-apply regardless of hash
            false, // dry_run
            false, // no_tripwire
            param_overrides,
            false, // auto_commit
            timeout,
            false, // json
            false, // verbose
            None,  // env_file
            None,  // workspace
            false, // report
            false, // force_unlock
            None,  // output_mode
            false, // progress
            false, // timing
            0,     // retry
            true,  // yes — no confirmation
            false, // parallel
            None,  // resource_timeout
            false, // rollback_on_failure
            None,  // max_parallel
            None,  // notify,
            None,  // subset
            false, // confirm_destructive
            None,  // exclude
            false, // sequential
        )?;
    }

    println!(
        "\n{} Retried {} resource(s) successfully.",
        green("✓"),
        failed_resources.len()
    );
    Ok(())
}

/// FJ-324: Rolling deployment — apply N machines at a time, stop on failure.
fn cmd_rolling(
    file: &Path,
    state_dir: &Path,
    batch_size: usize,
    param_overrides: &[String],
    timeout: Option<u64>,
) -> Result<(), String> {
    let config = parse_and_validate(file)?;
    let machine_names: Vec<String> = config.machines.keys().cloned().collect();

    if machine_names.is_empty() {
        return Err("no machines defined in config".to_string());
    }

    let batches: Vec<Vec<String>> = machine_names
        .chunks(batch_size)
        .map(|chunk| chunk.to_vec())
        .collect();

    println!(
        "Rolling deploy: {} machines in {} batch(es) of {}",
        machine_names.len(),
        batches.len(),
        batch_size,
    );

    for (i, batch) in batches.iter().enumerate() {
        println!(
            "\n--- Batch {}/{}: {} ---",
            i + 1,
            batches.len(),
            batch.join(", ")
        );

        for machine in batch {
            cmd_apply(
                file,
                state_dir,
                Some(machine),
                None,  // resource_filter
                None,  // tag_filter
                None,  // group_filter
                false, // force
                false, // dry_run
                false, // no_tripwire
                param_overrides,
                false, // auto_commit
                timeout,
                false, // json
                false, // verbose
                None,  // env_file
                None,  // workspace
                false, // report
                false, // force_unlock
                None,  // output_mode
                false, // progress
                false, // timing
                0,     // retry
                true,  // yes
                false, // parallel
                None,  // resource_timeout
                false, // rollback_on_failure
                None,  // max_parallel
                None,  // notify,
                None,  // subset
                false, // confirm_destructive
                None,  // exclude
                false, // sequential
            )?;
        }

        println!("Batch {}/{} complete.", i + 1, batches.len());
    }

    println!(
        "\n{} Rolling deploy complete: {} machines converged.",
        green("✓"),
        machine_names.len()
    );
    Ok(())
}

/// FJ-325: Canary deployment — apply to one machine first, then rest.
fn cmd_canary(
    file: &Path,
    state_dir: &Path,
    canary_machine: &str,
    auto_proceed: bool,
    param_overrides: &[String],
    timeout: Option<u64>,
) -> Result<(), String> {
    let config = parse_and_validate(file)?;

    if !config.machines.contains_key(canary_machine) {
        return Err(format!(
            "canary machine '{}' not found in config (available: {})",
            canary_machine,
            config
                .machines
                .keys()
                .cloned()
                .collect::<Vec<_>>()
                .join(", ")
        ));
    }

    // Phase 1: Apply to canary
    println!("=== Canary Phase: applying to '{}' ===\n", canary_machine);

    cmd_apply(
        file,
        state_dir,
        Some(canary_machine),
        None,
        None,
        None,
        false,
        false,
        false,
        param_overrides,
        false,
        timeout,
        false,
        false,
        None,
        None,
        false,
        false,
        None,
        false,
        false,
        0,
        true,
        false,
        None,
        false,
        None,
        None,
        None,  // subset
        false, // confirm_destructive
        None,  // exclude
        false, // sequential
    )?;

    println!("\n{} Canary '{}' succeeded.", green("✓"), canary_machine);

    // Phase 2: Apply to remaining machines
    let remaining: Vec<String> = config
        .machines
        .keys()
        .filter(|k| *k != canary_machine)
        .cloned()
        .collect();

    if remaining.is_empty() {
        println!("No remaining machines. Canary deploy complete.");
        return Ok(());
    }

    if !auto_proceed {
        println!(
            "\nCanary succeeded. Remaining machines: {}",
            remaining.join(", ")
        );
        println!("Use --auto-proceed to skip this confirmation in CI.");
        println!("Proceeding to remaining machines...");
    }

    println!(
        "\n=== Fleet Phase: applying to {} remaining machine(s) ===\n",
        remaining.len()
    );

    for machine in &remaining {
        cmd_apply(
            file,
            state_dir,
            Some(machine),
            None,
            None,
            None,
            false,
            false,
            false,
            param_overrides,
            false,
            timeout,
            false,
            false,
            None,
            None,
            false,
            false,
            None,
            false,
            false,
            0,
            true,
            false,
            None,
            false,
            None,
            None,
            None,  // subset
            false, // confirm_destructive
            None,  // exclude
            false, // sequential
        )?;
    }

    println!(
        "\n{} Canary deploy complete: canary + {} machine(s) converged.",
        green("✓"),
        remaining.len()
    );
    Ok(())
}

/// Simple glob matching — supports `*` wildcard at start/end/both.
fn simple_glob_match(pattern: &str, text: &str) -> bool {
    if pattern == "*" {
        return true;
    }
    let starts_with_star = pattern.starts_with('*');
    let ends_with_star = pattern.ends_with('*');
    let core = pattern.trim_matches('*');

    match (starts_with_star, ends_with_star) {
        (true, true) => text.contains(core),
        (true, false) => text.ends_with(core),
        (false, true) => text.starts_with(core),
        (false, false) => text == pattern,
    }
}

/// FJ-336: Show resources not updated in N days.
fn cmd_status_stale(
    state_dir: &Path,
    machine_filter: Option<&str>,
    days: u64,
    json: bool,
) -> Result<(), String> {
    let cutoff = std::time::SystemTime::now() - std::time::Duration::from_secs(days * 86400);

    let entries = std::fs::read_dir(state_dir)
        .map_err(|e| format!("cannot read state dir {}: {}", state_dir.display(), e))?;

    let mut stale_resources: Vec<serde_json::Value> = Vec::new();

    for entry in entries.flatten() {
        let name = entry.file_name().to_string_lossy().to_string();
        if let Some(filter) = machine_filter {
            if name != filter {
                continue;
            }
        }
        if !entry.path().is_dir() {
            continue;
        }

        let lock_path = entry.path().join("lock.yaml");
        if !lock_path.exists() {
            continue;
        }

        let content = std::fs::read_to_string(&lock_path)
            .map_err(|e| format!("cannot read {}: {}", lock_path.display(), e))?;
        if let Ok(lock) = serde_yaml_ng::from_str::<types::StateLock>(&content) {
            for (resource_id, resource_state) in &lock.resources {
                // Use lock file mtime as proxy for last-applied time
                let stale = if let Ok(meta) = std::fs::metadata(&lock_path) {
                    meta.modified().map(|m| m < cutoff).unwrap_or(false)
                } else {
                    false
                };

                if stale {
                    stale_resources.push(serde_json::json!({
                        "machine": name,
                        "resource": resource_id,
                        "last_applied": resource_state.applied_at,
                        "days_stale": days,
                    }));

                    if !json {
                        println!(
                            "  {} {} → {} (not updated in {}+ days)",
                            yellow("⚠"),
                            name,
                            resource_id,
                            days
                        );
                    }
                }
            }
        }
    }

    if json {
        println!(
            "{}",
            serde_json::to_string_pretty(&stale_resources).unwrap_or_default()
        );
    } else if stale_resources.is_empty() {
        println!("No stale resources found (threshold: {} days).", days);
    } else {
        println!(
            "\n{} stale resource(s) found (not updated in {}+ days).",
            stale_resources.len(),
            days
        );
    }

    Ok(())
}

/// Compact timestamp for snapshot names (YYYYMMDD-HHMMSS).
fn chrono_now_compact() -> String {
    let now = std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .unwrap_or_default()
        .as_secs();
    // Simple Unix timestamp — good enough for unique naming
    format!("{}", now)
}

/// FJ-341: Audit trail — who applied what, when, from which config.
fn cmd_audit(
    state_dir: &Path,
    machine_filter: Option<&str>,
    limit: usize,
    json: bool,
) -> Result<(), String> {
    let entries = std::fs::read_dir(state_dir)
        .map_err(|e| format!("cannot read state dir {}: {}", state_dir.display(), e))?;

    let mut all_events: Vec<(String, types::TimestampedEvent)> = Vec::new();

    for entry in entries.flatten() {
        let name = entry.file_name().to_string_lossy().to_string();
        if let Some(filter) = machine_filter {
            if name != filter {
                continue;
            }
        }
        if !entry.path().is_dir() {
            continue;
        }

        let log_path = eventlog::event_log_path(state_dir, &name);
        if !log_path.exists() {
            continue;
        }

        let content = std::fs::read_to_string(&log_path)
            .map_err(|e| format!("cannot read {}: {}", log_path.display(), e))?;

        for line in content.lines() {
            if line.trim().is_empty() {
                continue;
            }
            if let Ok(event) = serde_json::from_str::<types::TimestampedEvent>(line) {
                all_events.push((name.clone(), event));
            }
        }
    }

    // Sort by timestamp descending
    all_events.sort_by(|a, b| b.1.ts.cmp(&a.1.ts));
    all_events.truncate(limit);

    if json {
        let json_events: Vec<serde_json::Value> = all_events
            .iter()
            .map(|(machine, ev)| {
                serde_json::json!({
                    "machine": machine,
                    "timestamp": ev.ts,
                    "event": format!("{:?}", ev.event),
                })
            })
            .collect();
        println!(
            "{}",
            serde_json::to_string_pretty(&json_events).unwrap_or_default()
        );
    } else {
        if all_events.is_empty() {
            println!("No audit events found.");
            return Ok(());
        }
        println!("Audit trail (last {} events):\n", limit);
        for (machine, ev) in &all_events {
            println!("  {} [{}] {:?}", ev.ts, machine, ev.event);
        }
    }

    Ok(())
}

/// FJ-344: Compact one-line-per-resource plan output.
fn cmd_plan_compact(
    file: &Path,
    state_dir: &Path,
    machine_filter: Option<&str>,
    json: bool,
) -> Result<(), String> {
    let config = parse_and_validate(file)?;
    let execution_order = resolver::build_execution_order(&config)?;
    let locks = load_machine_locks(&config, state_dir, machine_filter)?;
    let plan = planner::plan(&config, &execution_order, &locks, None);

    if json {
        let compact: Vec<serde_json::Value> = plan
            .changes
            .iter()
            .map(|c| {
                serde_json::json!({
                    "resource": c.resource_id,
                    "action": format!("{:?}", c.action),
                    "machine": c.machine,
                })
            })
            .collect();
        println!(
            "{}",
            serde_json::to_string_pretty(&compact).unwrap_or_default()
        );
    } else {
        for change in &plan.changes {
            let icon = match change.action {
                types::PlanAction::Create => green("+"),
                types::PlanAction::Update => yellow("~"),
                types::PlanAction::Destroy => red("-"),
                types::PlanAction::NoOp => dim("="),
            };
            println!("  {} {} ({})", icon, change.resource_id, change.machine,);
        }
        println!(
            "\n{} change(s)",
            plan.changes
                .iter()
                .filter(|c| c.action != types::PlanAction::NoOp)
                .count()
        );
    }

    Ok(())
}

/// FJ-343: Doctor network check — test SSH to all machines.
fn cmd_doctor_network(file: Option<&Path>, json: bool) -> Result<(), String> {
    let config_path = file.unwrap_or_else(|| std::path::Path::new("forjar.yaml"));
    let config = parse_and_validate(config_path)?;

    let mut results: Vec<serde_json::Value> = Vec::new();

    for (name, machine) in &config.machines {
        let is_local = machine.addr == "127.0.0.1" || machine.addr == "localhost";

        let (status, latency_ms) = if is_local {
            ("reachable".to_string(), 0u64)
        } else {
            let start = std::time::Instant::now();
            let user_host = format!("{}@{}", machine.user, machine.addr);
            let mut ssh_args = vec!["-o", "BatchMode=yes", "-o", "ConnectTimeout=5"];
            if let Some(ref key) = machine.ssh_key {
                ssh_args.push("-i");
                ssh_args.push(key);
            }
            ssh_args.push(&user_host);
            ssh_args.push("echo");
            ssh_args.push("ok");
            let result = std::process::Command::new("ssh")
                .args(&ssh_args)
                .stdout(std::process::Stdio::null())
                .stderr(std::process::Stdio::null())
                .status();
            let elapsed = start.elapsed().as_millis() as u64;
            match result {
                Ok(s) if s.success() => ("reachable".to_string(), elapsed),
                _ => ("unreachable".to_string(), elapsed),
            }
        };

        if json {
            results.push(serde_json::json!({
                "machine": name,
                "addr": machine.addr,
                "status": status,
                "latency_ms": latency_ms,
            }));
        } else {
            let icon = if status == "reachable" {
                green("●")
            } else {
                red("✗")
            };
            println!(
                "  {} {} ({}) — {} ({}ms)",
                icon, name, machine.addr, status, latency_ms
            );
        }
    }

    if json {
        println!(
            "{}",
            serde_json::to_string_pretty(&results).unwrap_or_default()
        );
    }

    Ok(())
}

/// FJ-346: Status health score (0-100).
fn cmd_status_health(
    state_dir: &Path,
    machine_filter: Option<&str>,
    json: bool,
) -> Result<(), String> {
    let entries = std::fs::read_dir(state_dir)
        .map_err(|e| format!("cannot read state dir {}: {}", state_dir.display(), e))?;

    let mut total_resources = 0u32;
    let mut converged = 0u32;
    let mut failed = 0u32;

    for entry in entries.flatten() {
        let name = entry.file_name().to_string_lossy().to_string();
        if let Some(filter) = machine_filter {
            if name != filter {
                continue;
            }
        }
        if !entry.path().is_dir() {
            continue;
        }

        let lock_path = entry.path().join("lock.yaml");
        if !lock_path.exists() {
            continue;
        }

        let content = std::fs::read_to_string(&lock_path)
            .map_err(|e| format!("cannot read {}: {}", lock_path.display(), e))?;
        if let Ok(lock) = serde_yaml_ng::from_str::<types::StateLock>(&content) {
            for (_id, resource) in &lock.resources {
                total_resources += 1;
                match resource.status {
                    types::ResourceStatus::Converged => converged += 1,
                    types::ResourceStatus::Failed => failed += 1,
                    _ => {}
                }
            }
        }
    }

    let score = if total_resources == 0 {
        100u32
    } else {
        ((converged as f64 / total_resources as f64) * 100.0) as u32
    };

    if json {
        println!(
            "{}",
            serde_json::to_string_pretty(&serde_json::json!({
                "health_score": score,
                "total": total_resources,
                "converged": converged,
                "failed": failed,
            }))
            .unwrap_or_default()
        );
    } else {
        let color_fn = if score >= 80 {
            green
        } else if score >= 50 {
            yellow
        } else {
            red
        };
        println!(
            "Health: {} ({}/{} converged, {} failed)",
            color_fn(&format!("{}%", score)),
            converged,
            total_resources,
            failed
        );
    }

    Ok(())
}

// FJ-354: Show transitive dependents of a resource
fn cmd_graph_affected(file: &Path, resource: &str) -> Result<(), String> {
    let config = parse_and_validate(file)?;

    if !config.resources.contains_key(resource) {
        return Err(format!("Resource '{}' not found in config", resource));
    }

    // Build reverse dependency map
    let mut dependents: std::collections::HashMap<String, Vec<String>> =
        std::collections::HashMap::new();
    for (id, res) in &config.resources {
        for dep in &res.depends_on {
            dependents.entry(dep.clone()).or_default().push(id.clone());
        }
    }

    // BFS to find all transitive dependents
    let mut affected = Vec::new();
    let mut queue = std::collections::VecDeque::new();
    let mut visited = std::collections::HashSet::new();
    queue.push_back(resource.to_string());
    visited.insert(resource.to_string());

    while let Some(current) = queue.pop_front() {
        if let Some(deps) = dependents.get(&current) {
            for dep in deps {
                if visited.insert(dep.clone()) {
                    affected.push(dep.clone());
                    queue.push_back(dep.clone());
                }
            }
        }
    }

    affected.sort();

    println!("Resources affected by changes to '{}':\n", bold(resource));
    if affected.is_empty() {
        println!("  (none — no resources depend on '{}')", resource);
    } else {
        for a in &affected {
            println!("  {} {}", yellow("→"), a);
        }
        println!(
            "\n{} {} transitive dependent(s)",
            green("Total:"),
            affected.len()
        );
    }

    Ok(())
}

// FJ-357: Show change history for a specific resource
fn cmd_history_resource(
    state_dir: &Path,
    resource: &str,
    limit: usize,
    json: bool,
) -> Result<(), String> {
    let log_dir = state_dir.join("events");
    if !log_dir.exists() {
        if json {
            println!("[]");
        } else {
            println!("No event logs found.");
        }
        return Ok(());
    }

    let mut entries: Vec<String> = Vec::new();
    for entry in std::fs::read_dir(&log_dir).map_err(|e| e.to_string())? {
        let entry = entry.map_err(|e| e.to_string())?;
        let path = entry.path();
        if path.extension().is_some_and(|e| e == "jsonl") {
            let content = std::fs::read_to_string(&path).map_err(|e| e.to_string())?;
            for line in content.lines() {
                if line.contains(resource) {
                    entries.push(line.to_string());
                }
            }
        }
    }

    entries.sort();
    if entries.len() > limit {
        entries = entries.split_off(entries.len() - limit);
    }

    if json {
        println!("[{}]", entries.join(","));
    } else {
        println!("History for resource '{}':\n", bold(resource));
        if entries.is_empty() {
            println!("  (no events found)");
        } else {
            for entry in &entries {
                println!("  {}", entry);
            }
        }
    }

    Ok(())
}

// FJ-355: Show detailed drift report with field-level diffs
fn cmd_status_drift_details(
    state_dir: &Path,
    machine_filter: Option<&str>,
    json: bool,
) -> Result<(), String> {
    let entries =
        std::fs::read_dir(state_dir).map_err(|e| format!("cannot read state dir: {}", e))?;

    let mut details = Vec::new();
    for entry in entries.flatten() {
        let name = entry.file_name().to_string_lossy().to_string();
        if let Some(filter) = machine_filter {
            if name != filter {
                continue;
            }
        }
        if !entry.path().is_dir() {
            continue;
        }
        if let Some(lock) = state::load_lock(state_dir, &name)? {
            for (id, rl) in &lock.resources {
                if matches!(
                    rl.status,
                    types::ResourceStatus::Drifted | types::ResourceStatus::Failed
                ) {
                    details.push(serde_json::json!({
                        "resource": id,
                        "machine": lock.machine,
                        "status": format!("{:?}", rl.status),
                        "hash": rl.hash,
                        "applied_at": rl.applied_at,
                    }));
                }
            }
        }
    }

    if json {
        println!(
            "{}",
            serde_json::to_string_pretty(&details).unwrap_or_else(|_| "[]".to_string())
        );
    } else {
        println!("Drift Details:\n");
        if details.is_empty() {
            println!("  {} No drift detected.", green("✓"));
        } else {
            for d in &details {
                println!(
                    "  {} {} on {} — {} ({})",
                    yellow("~"),
                    d["resource"].as_str().unwrap_or("?"),
                    d["machine"].as_str().unwrap_or("?"),
                    d["status"].as_str().unwrap_or("?"),
                    d["applied_at"].as_str().unwrap_or("?"),
                );
            }
            println!(
                "\n{} {} resource(s) with drift",
                yellow("Total:"),
                details.len()
            );
        }
    }

    Ok(())
}

// FJ-351: Validate infrastructure against policy rules
fn cmd_compliance(file: &Path, json: bool) -> Result<(), String> {
    let config = parse_and_validate(file)?;
    let mut violations = Vec::new();

    for (id, res) in &config.resources {
        // Check: resources should have depends_on or be root resources
        // Check: file resources should have mode set
        if res.resource_type == crate::core::types::ResourceType::File {
            if res.mode.is_none() {
                violations.push(serde_json::json!({
                    "resource": id,
                    "rule": "file-mode-required",
                    "severity": "warning",
                    "message": format!("File resource '{}' has no mode set", id),
                }));
            }
            if res.owner.is_none() {
                violations.push(serde_json::json!({
                    "resource": id,
                    "rule": "file-owner-required",
                    "severity": "warning",
                    "message": format!("File resource '{}' has no owner set", id),
                }));
            }
        }

        // Check: service resources should set enabled explicitly
        if res.resource_type == crate::core::types::ResourceType::Service && res.enabled.is_none() {
            violations.push(serde_json::json!({
                "resource": id,
                "rule": "service-enabled-required",
                "severity": "warning",
                "message": format!("Service resource '{}' does not set 'enabled' explicitly", id),
            }));
        }

        // Check: resources should not use root paths without explicit owner
        if let Some(ref path) = res.path {
            if (path.starts_with("/etc/") || path.starts_with("/usr/")) && res.owner.is_none() {
                violations.push(serde_json::json!({
                    "resource": id,
                    "rule": "system-path-owner-required",
                    "severity": "error",
                    "message": format!("Resource '{}' writes to system path '{}' without explicit owner", id, path),
                }));
            }
        }
    }

    if json {
        println!(
            "{}",
            serde_json::to_string_pretty(&violations).unwrap_or_else(|_| "[]".to_string())
        );
    } else if violations.is_empty() {
        println!("{} All compliance checks passed.", green("✓"));
    } else {
        println!("Compliance violations:\n");
        for v in &violations {
            let icon = if v["severity"] == "error" {
                red("✗")
            } else {
                yellow("!")
            };
            println!(
                "  {} [{}] {}",
                icon,
                v["rule"].as_str().unwrap_or("?"),
                v["message"].as_str().unwrap_or("?"),
            );
        }
        println!(
            "\n{} {} violation(s) found",
            yellow("Total:"),
            violations.len()
        );
    }

    Ok(())
}

// FJ-352: Export state to external formats
fn cmd_export(
    state_dir: &Path,
    format: &str,
    machine_filter: Option<&str>,
    output: Option<&Path>,
) -> Result<(), String> {
    let entries =
        std::fs::read_dir(state_dir).map_err(|e| format!("cannot read state dir: {}", e))?;

    // Collect all resources across machines
    let mut all_resources: Vec<(String, String, types::ResourceLock)> = Vec::new();
    for entry in entries.flatten() {
        let name = entry.file_name().to_string_lossy().to_string();
        if let Some(filter) = machine_filter {
            if name != filter {
                continue;
            }
        }
        if !entry.path().is_dir() {
            continue;
        }
        if let Some(lock) = state::load_lock(state_dir, &name)? {
            for (id, rl) in lock.resources {
                all_resources.push((id, lock.machine.clone(), rl));
            }
        }
    }

    let content = match format {
        "csv" => {
            let mut lines = vec!["resource,machine,type,status,hash,applied_at".to_string()];
            for (id, machine, rl) in &all_resources {
                lines.push(format!(
                    "{},{},{:?},{:?},{},{}",
                    id,
                    machine,
                    rl.resource_type,
                    rl.status,
                    rl.hash,
                    rl.applied_at.as_deref().unwrap_or("-")
                ));
            }
            lines.join("\n")
        }
        "terraform" => {
            let mut blocks = Vec::new();
            for (id, _machine, rl) in &all_resources {
                blocks.push(format!(
                    "# {}\nimport {{\n  to = forjar_resource.{}\n  id = \"{}\"\n}}",
                    id, id, rl.hash
                ));
            }
            blocks.join("\n\n")
        }
        "ansible" => {
            let mut machines: std::collections::BTreeMap<&str, Vec<&str>> =
                std::collections::BTreeMap::new();
            for (id, machine, _rl) in &all_resources {
                machines
                    .entry(machine.as_str())
                    .or_default()
                    .push(id.as_str());
            }
            let mut lines = vec!["all:".to_string(), "  hosts:".to_string()];
            for (machine, resources) in &machines {
                lines.push(format!("    {}:", machine));
                lines.push("      forjar_resources:".to_string());
                for res in resources {
                    lines.push(format!("        - {}", res));
                }
            }
            lines.join("\n")
        }
        _ => {
            return Err(format!(
                "Unknown export format '{}'. Supported: csv, terraform, ansible",
                format
            ))
        }
    };

    if let Some(output_path) = output {
        std::fs::write(output_path, &content).map_err(|e| e.to_string())?;
        println!(
            "Exported {} resources to {}",
            all_resources.len(),
            output_path.display()
        );
    } else {
        println!("{}", content);
    }

    Ok(())
}

// FJ-361: Suggest improvements to config
fn cmd_suggest(file: &Path, json: bool) -> Result<(), String> {
    let config = parse_and_validate(file)?;
    let mut suggestions = Vec::new();

    // Check for unused params
    let config_str = std::fs::read_to_string(file).map_err(|e| e.to_string())?;
    for key in config.params.keys() {
        let pattern = format!("{{{{params.{}}}}}", key);
        if !config_str.contains(&pattern) {
            suggestions.push(serde_json::json!({
                "type": "unused-param",
                "severity": "info",
                "message": format!("Parameter '{}' is defined but never referenced", key),
            }));
        }
    }

    // Check for missing depends_on (resources on same machine that could race)
    let machine_resources: std::collections::HashMap<String, Vec<String>> = {
        let mut m: std::collections::HashMap<String, Vec<String>> =
            std::collections::HashMap::new();
        for (id, res) in &config.resources {
            let machine_name = match &res.machine {
                types::MachineTarget::Single(s) => s.clone(),
                types::MachineTarget::Multiple(ms) => ms.first().cloned().unwrap_or_default(),
            };
            m.entry(machine_name).or_default().push(id.clone());
        }
        m
    };
    for resources in machine_resources.values() {
        if resources.len() > 1 {
            for id in resources {
                let res = &config.resources[id];
                if res.depends_on.is_empty() {
                    // Check if this resource has any other resource that depends on it
                    let has_dependent =
                        config.resources.values().any(|r| r.depends_on.contains(id));
                    if !has_dependent && resources.len() > 2 {
                        suggestions.push(serde_json::json!({
                            "type": "no-dependencies",
                            "severity": "info",
                            "message": format!("Resource '{}' has no depends_on and nothing depends on it — verify ordering", id),
                        }));
                    }
                }
            }
        }
    }

    if json {
        println!(
            "{}",
            serde_json::to_string_pretty(&suggestions).unwrap_or_else(|_| "[]".to_string())
        );
    } else if suggestions.is_empty() {
        println!("{} No suggestions — config looks good.", green("✓"));
    } else {
        println!("Suggestions:\n");
        for s in &suggestions {
            println!(
                "  {} [{}] {}",
                dim("→"),
                s["type"].as_str().unwrap_or("?"),
                s["message"].as_str().unwrap_or("?"),
            );
        }
        println!("\n{} {} suggestion(s)", dim("Total:"), suggestions.len());
    }

    Ok(())
}

// FJ-363: Compare two config files
fn cmd_compare(file1: &Path, file2: &Path, json: bool) -> Result<(), String> {
    let config1 = parse_and_validate(file1)?;
    let config2 = parse_and_validate(file2)?;

    let keys1: std::collections::HashSet<&String> = config1.resources.keys().collect();
    let keys2: std::collections::HashSet<&String> = config2.resources.keys().collect();

    let only_in_1: Vec<&&String> = keys1.difference(&keys2).collect();
    let only_in_2: Vec<&&String> = keys2.difference(&keys1).collect();
    let in_both: Vec<&&String> = keys1.intersection(&keys2).collect();

    let mut changed = Vec::new();
    for key in &in_both {
        let r1 = &config1.resources[**key];
        let r2 = &config2.resources[**key];
        // Compare by hashing the serialized forms
        let s1 = format!("{:?}", r1);
        let s2 = format!("{:?}", r2);
        if s1 != s2 {
            changed.push(**key);
        }
    }

    if json {
        let result = serde_json::json!({
            "only_in_first": only_in_1,
            "only_in_second": only_in_2,
            "changed": changed,
            "unchanged": in_both.len() - changed.len(),
        });
        println!(
            "{}",
            serde_json::to_string_pretty(&result).unwrap_or_else(|_| "{}".to_string())
        );
    } else {
        println!("Comparing {} vs {}\n", file1.display(), file2.display());
        for k in &only_in_1 {
            println!("  {} {} (only in {})", red("-"), k, file1.display());
        }
        for k in &only_in_2 {
            println!("  {} {} (only in {})", green("+"), k, file2.display());
        }
        for k in &changed {
            println!("  {} {} (modified)", yellow("~"), k);
        }
        let unchanged = in_both.len() - changed.len();
        if unchanged > 0 {
            println!("  {} {} resource(s) unchanged", dim("="), unchanged);
        }
    }

    Ok(())
}

// FJ-364: Status timeline
fn cmd_status_timeline(
    state_dir: &Path,
    machine_filter: Option<&str>,
    json: bool,
) -> Result<(), String> {
    let entries =
        std::fs::read_dir(state_dir).map_err(|e| format!("cannot read state dir: {}", e))?;

    let mut timeline: Vec<serde_json::Value> = Vec::new();
    for entry in entries.flatten() {
        let name = entry.file_name().to_string_lossy().to_string();
        if let Some(filter) = machine_filter {
            if name != filter {
                continue;
            }
        }
        if !entry.path().is_dir() {
            continue;
        }
        if let Some(lock) = state::load_lock(state_dir, &name)? {
            for (id, rl) in &lock.resources {
                timeline.push(serde_json::json!({
                    "resource": id,
                    "machine": lock.machine,
                    "status": format!("{:?}", rl.status),
                    "applied_at": rl.applied_at,
                    "duration_seconds": rl.duration_seconds,
                }));
            }
        }
    }

    // Sort by applied_at
    timeline.sort_by(|a, b| {
        let ta = a["applied_at"].as_str().unwrap_or("");
        let tb = b["applied_at"].as_str().unwrap_or("");
        ta.cmp(tb)
    });

    if json {
        println!(
            "{}",
            serde_json::to_string_pretty(&timeline).unwrap_or_else(|_| "[]".to_string())
        );
    } else {
        println!("Convergence Timeline:\n");
        if timeline.is_empty() {
            println!("  (no data)");
        } else {
            for t in &timeline {
                let status_icon = match t["status"].as_str().unwrap_or("") {
                    "Converged" => green("✓"),
                    "Failed" => red("✗"),
                    "Drifted" => yellow("~"),
                    _ => dim("?"),
                };
                println!(
                    "  {} {} {} on {} ({}s)",
                    t["applied_at"].as_str().unwrap_or("-"),
                    status_icon,
                    t["resource"].as_str().unwrap_or("?"),
                    t["machine"].as_str().unwrap_or("?"),
                    t["duration_seconds"]
                        .as_f64()
                        .map(|d| format!("{:.2}", d))
                        .unwrap_or_else(|| "-".to_string()),
                );
            }
        }
    }

    Ok(())
}

// FJ-366: Lock prune — remove stale lock entries
fn cmd_lock_prune(file: &Path, state_dir: &Path, yes: bool) -> Result<(), String> {
    let config = parse_and_validate(file)?;
    let config_resources: std::collections::HashSet<&String> = config.resources.keys().collect();

    let entries =
        std::fs::read_dir(state_dir).map_err(|e| format!("cannot read state dir: {}", e))?;

    let mut pruned = 0usize;
    for entry in entries.flatten() {
        if !entry.path().is_dir() {
            continue;
        }
        let machine_name = entry.file_name().to_string_lossy().to_string();
        if let Some(lock) = state::load_lock(state_dir, &machine_name)? {
            let stale: Vec<String> = lock
                .resources
                .keys()
                .filter(|k| !config_resources.contains(k))
                .cloned()
                .collect();

            if stale.is_empty() {
                continue;
            }

            for s in &stale {
                if yes {
                    println!("  {} Pruned '{}' from {}", red("-"), s, machine_name);
                } else {
                    println!(
                        "  {} Would prune '{}' from {} (use --yes to apply)",
                        yellow("~"),
                        s,
                        machine_name
                    );
                }
            }
            pruned += stale.len();
        }
    }

    if pruned == 0 {
        println!("{} No stale lock entries found.", green("✓"));
    } else if !yes {
        println!(
            "\n{} {} stale entries. Run with --yes to prune.",
            yellow("Total:"),
            pruned
        );
    } else {
        println!("\n{} Pruned {} stale entries.", green("✓"), pruned);
    }

    Ok(())
}

// FJ-367: Compare environments (workspaces)
fn cmd_env_diff(env1: &str, env2: &str, state_dir: &Path, json: bool) -> Result<(), String> {
    let dir1 = state_dir.join(env1);
    let dir2 = state_dir.join(env2);

    if !dir1.exists() {
        return Err(format!(
            "Workspace '{}' not found at {}",
            env1,
            dir1.display()
        ));
    }
    if !dir2.exists() {
        return Err(format!(
            "Workspace '{}' not found at {}",
            env2,
            dir2.display()
        ));
    }

    // Load all locks from both environments
    let mut resources1: std::collections::HashMap<String, String> =
        std::collections::HashMap::new();
    let mut resources2: std::collections::HashMap<String, String> =
        std::collections::HashMap::new();

    for entry in std::fs::read_dir(&dir1)
        .map_err(|e| e.to_string())?
        .flatten()
    {
        if entry.path().is_dir() {
            let name = entry.file_name().to_string_lossy().to_string();
            if let Some(lock) = state::load_lock(&dir1, &name)? {
                for (id, rl) in &lock.resources {
                    resources1.insert(format!("{}:{}", name, id), rl.hash.clone());
                }
            }
        }
    }
    for entry in std::fs::read_dir(&dir2)
        .map_err(|e| e.to_string())?
        .flatten()
    {
        if entry.path().is_dir() {
            let name = entry.file_name().to_string_lossy().to_string();
            if let Some(lock) = state::load_lock(&dir2, &name)? {
                for (id, rl) in &lock.resources {
                    resources2.insert(format!("{}:{}", name, id), rl.hash.clone());
                }
            }
        }
    }

    let keys1: std::collections::HashSet<&String> = resources1.keys().collect();
    let keys2: std::collections::HashSet<&String> = resources2.keys().collect();

    let only1: Vec<&&String> = keys1.difference(&keys2).collect();
    let only2: Vec<&&String> = keys2.difference(&keys1).collect();
    let mut drifted = Vec::new();
    for key in keys1.intersection(&keys2) {
        if resources1[*key] != resources2[*key] {
            drifted.push(*key);
        }
    }

    if json {
        let result = serde_json::json!({
            "only_in_first": only1,
            "only_in_second": only2,
            "drifted": drifted,
        });
        println!(
            "{}",
            serde_json::to_string_pretty(&result).unwrap_or_else(|_| "{}".to_string())
        );
    } else {
        println!("Environment diff: {} vs {}\n", bold(env1), bold(env2));
        for k in &only1 {
            println!("  {} {} (only in {})", red("-"), k, env1);
        }
        for k in &only2 {
            println!("  {} {} (only in {})", green("+"), k, env2);
        }
        for k in &drifted {
            println!("  {} {} (hash differs)", yellow("~"), k);
        }
        if only1.is_empty() && only2.is_empty() && drifted.is_empty() {
            println!("  {} Environments are identical.", green("✓"));
        }
    }

    Ok(())
}

// FJ-371: Expand recipe template to stdout
fn cmd_template(recipe: &Path, vars: &[String], json: bool) -> Result<(), String> {
    let content = std::fs::read_to_string(recipe)
        .map_err(|e| format!("cannot read recipe {}: {}", recipe.display(), e))?;

    // Parse vars into map
    let mut var_map = std::collections::HashMap::new();
    for v in vars {
        if let Some((key, val)) = v.split_once('=') {
            var_map.insert(key.to_string(), val.to_string());
        }
    }

    // Simple template expansion: replace {{inputs.KEY}} with value
    let mut expanded = content.clone();
    for (key, val) in &var_map {
        let pattern = format!("{{{{inputs.{}}}}}", key);
        expanded = expanded.replace(&pattern, val);
    }

    if json {
        println!(
            "{}",
            serde_json::json!({
                "recipe": recipe.display().to_string(),
                "vars": var_map,
                "expanded": expanded,
            })
        );
    } else {
        println!("{}", expanded);
    }

    Ok(())
}

// FJ-372: Show resources changed since a git commit
fn cmd_status_changes_since(state_dir: &Path, commit: &str, json: bool) -> Result<(), String> {
    // Use git diff to find changed state files
    let output = std::process::Command::new("git")
        .args([
            "diff",
            "--name-only",
            commit,
            "--",
            &state_dir.display().to_string(),
        ])
        .output()
        .map_err(|e| format!("git diff failed: {}", e))?;

    let stdout = String::from_utf8_lossy(&output.stdout);
    let changed: Vec<&str> = stdout.lines().filter(|l| !l.is_empty()).collect();

    if json {
        println!(
            "{}",
            serde_json::to_string_pretty(&changed).unwrap_or_else(|_| "[]".to_string())
        );
    } else {
        println!("Resources changed since {}:\n", bold(commit));
        if changed.is_empty() {
            println!("  {} No changes.", green("✓"));
        } else {
            for c in &changed {
                println!("  {} {}", yellow("~"), c);
            }
        }
    }

    Ok(())
}

// FJ-375: Critical path — longest dependency chain
fn cmd_graph_critical_path(file: &Path) -> Result<(), String> {
    let config = parse_and_validate(file)?;

    // Build adjacency list
    let mut adj: std::collections::HashMap<&str, Vec<&str>> = std::collections::HashMap::new();
    for (id, res) in &config.resources {
        for dep in &res.depends_on {
            adj.entry(dep.as_str()).or_default().push(id.as_str());
        }
    }

    // Find longest path via DFS from each root
    fn dfs<'a>(
        node: &'a str,
        adj: &std::collections::HashMap<&str, Vec<&'a str>>,
        memo: &mut std::collections::HashMap<&'a str, Vec<&'a str>>,
    ) -> Vec<&'a str> {
        if let Some(cached) = memo.get(node) {
            return cached.clone();
        }
        let mut longest = Vec::new();
        if let Some(children) = adj.get(node) {
            for child in children {
                let path = dfs(child, adj, memo);
                if path.len() > longest.len() {
                    longest = path;
                }
            }
        }
        let mut result = vec![node];
        result.extend(longest);
        memo.insert(node, result.clone());
        result
    }

    let mut memo = std::collections::HashMap::new();
    let mut critical = Vec::new();
    for id in config.resources.keys() {
        let path = dfs(id, &adj, &mut memo);
        if path.len() > critical.len() {
            critical = path;
        }
    }

    println!("Critical path ({} resources):\n", critical.len());
    for (i, node) in critical.iter().enumerate() {
        let prefix = if i == 0 {
            "┌"
        } else if i == critical.len() - 1 {
            "└"
        } else {
            "│"
        };
        println!("  {} {}", prefix, bold(node));
    }

    Ok(())
}

// FJ-376: Status summary-by dimension
fn cmd_status_summary_by(
    state_dir: &Path,
    machine_filter: Option<&str>,
    dimension: &str,
    json: bool,
) -> Result<(), String> {
    let entries =
        std::fs::read_dir(state_dir).map_err(|e| format!("cannot read state dir: {}", e))?;

    let mut groups: std::collections::BTreeMap<String, Vec<String>> =
        std::collections::BTreeMap::new();

    for entry in entries.flatten() {
        let name = entry.file_name().to_string_lossy().to_string();
        if let Some(filter) = machine_filter {
            if name != filter {
                continue;
            }
        }
        if !entry.path().is_dir() {
            continue;
        }
        if let Some(lock) = state::load_lock(state_dir, &name)? {
            for (id, rl) in &lock.resources {
                let key = match dimension {
                    "machine" => lock.machine.clone(),
                    "type" => format!("{:?}", rl.resource_type),
                    "status" => format!("{:?}", rl.status),
                    _ => {
                        return Err(format!(
                            "Unknown dimension '{}'. Use: machine, type, status",
                            dimension
                        ))
                    }
                };
                groups.entry(key).or_default().push(id.clone());
            }
        }
    }

    if json {
        println!(
            "{}",
            serde_json::to_string_pretty(&groups).unwrap_or_else(|_| "{}".to_string())
        );
    } else {
        println!("Summary by {}:\n", bold(dimension));
        for (group, resources) in &groups {
            println!("  {} ({}):", bold(group), resources.len());
            for r in resources {
                println!("    {}", r);
            }
        }
    }

    Ok(())
}

// FJ-382: Prometheus exposition format
fn cmd_status_prometheus(state_dir: &Path, machine_filter: Option<&str>) -> Result<(), String> {
    let entries =
        std::fs::read_dir(state_dir).map_err(|e| format!("cannot read state dir: {}", e))?;

    let mut converged = 0u64;
    let mut failed = 0u64;
    let mut drifted = 0u64;
    let mut total = 0u64;

    for entry in entries.flatten() {
        let name = entry.file_name().to_string_lossy().to_string();
        if let Some(filter) = machine_filter {
            if name != filter {
                continue;
            }
        }
        if !entry.path().is_dir() {
            continue;
        }
        if let Some(lock) = state::load_lock(state_dir, &name)? {
            for (_, rl) in &lock.resources {
                total += 1;
                match rl.status {
                    types::ResourceStatus::Converged => converged += 1,
                    types::ResourceStatus::Failed => failed += 1,
                    types::ResourceStatus::Drifted => drifted += 1,
                    types::ResourceStatus::Unknown => {}
                }
            }
        }
    }

    println!("# HELP forjar_resources_total Total managed resources");
    println!("# TYPE forjar_resources_total gauge");
    println!("forjar_resources_total {}", total);
    println!("# HELP forjar_resources_converged Converged resources");
    println!("# TYPE forjar_resources_converged gauge");
    println!("forjar_resources_converged {}", converged);
    println!("# HELP forjar_resources_failed Failed resources");
    println!("# TYPE forjar_resources_failed gauge");
    println!("forjar_resources_failed {}", failed);
    println!("# HELP forjar_resources_drifted Drifted resources");
    println!("# TYPE forjar_resources_drifted gauge");
    println!("forjar_resources_drifted {}", drifted);

    Ok(())
}

// FJ-384: Lock file metadata
fn cmd_lock_info(state_dir: &Path, json: bool) -> Result<(), String> {
    let entries =
        std::fs::read_dir(state_dir).map_err(|e| format!("cannot read state dir: {}", e))?;

    let mut machines = Vec::new();
    let mut total_resources = 0usize;

    for entry in entries.flatten() {
        if !entry.path().is_dir() {
            continue;
        }
        let name = entry.file_name().to_string_lossy().to_string();
        if let Some(lock) = state::load_lock(state_dir, &name)? {
            total_resources += lock.resources.len();
            machines.push(serde_json::json!({
                "machine": lock.machine,
                "hostname": lock.hostname,
                "schema": lock.schema,
                "generator": lock.generator,
                "generated_at": lock.generated_at,
                "resources": lock.resources.len(),
            }));
        }
    }

    if json {
        let result = serde_json::json!({
            "machines": machines,
            "total_resources": total_resources,
        });
        println!(
            "{}",
            serde_json::to_string_pretty(&result).unwrap_or_else(|_| "{}".to_string())
        );
    } else {
        println!("Lock Info:\n");
        println!("  Total machines: {}", machines.len());
        println!("  Total resources: {}", total_resources);
        for m in &machines {
            println!(
                "\n  {} ({}): {} resources, schema {}, generated {}",
                bold(m["machine"].as_str().unwrap_or("?")),
                m["hostname"].as_str().unwrap_or("?"),
                m["resources"],
                m["schema"].as_str().unwrap_or("?"),
                m["generated_at"].as_str().unwrap_or("?"),
            );
        }
    }

    Ok(())
}

// FJ-385: Reverse dependency graph
fn cmd_graph_reverse(file: &Path) -> Result<(), String> {
    let config = parse_and_validate(file)?;

    println!("Reverse Dependency Graph:\n");
    println!("(what depends on each resource)\n");

    let mut reverse_deps: std::collections::BTreeMap<String, Vec<String>> =
        std::collections::BTreeMap::new();
    for id in config.resources.keys() {
        reverse_deps.entry(id.clone()).or_default();
    }
    for (id, res) in &config.resources {
        for dep in &res.depends_on {
            reverse_deps
                .entry(dep.clone())
                .or_default()
                .push(id.clone());
        }
    }

    for (resource, dependents) in &reverse_deps {
        if dependents.is_empty() {
            println!(
                "  {} {} (leaf — nothing depends on this)",
                dim("○"),
                resource
            );
        } else {
            println!("  {} {} ({})", bold("●"), resource, dependents.len());
            for d in dependents {
                println!("    {} {}", yellow("←"), d);
            }
        }
    }

    Ok(())
}

// FJ-387: Show resources with expired lock entries
fn cmd_status_expired(
    state_dir: &Path,
    machine_filter: Option<&str>,
    duration: &str,
    json: bool,
) -> Result<(), String> {
    // Parse duration string (e.g., "7d", "24h", "30m")
    let seconds = parse_duration_string(duration)?;
    let now = std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .unwrap_or_default()
        .as_secs();
    let cutoff = now.saturating_sub(seconds);

    let entries =
        std::fs::read_dir(state_dir).map_err(|e| format!("cannot read state dir: {}", e))?;

    let mut expired = Vec::new();
    for entry in entries.flatten() {
        let name = entry.file_name().to_string_lossy().to_string();
        if let Some(filter) = machine_filter {
            if name != filter {
                continue;
            }
        }
        if !entry.path().is_dir() {
            continue;
        }
        if let Some(lock) = state::load_lock(state_dir, &name)? {
            for (id, rl) in &lock.resources {
                if let Some(ref at) = rl.applied_at {
                    // Simple heuristic: if applied_at is a parseable timestamp
                    if at.len() >= 10 {
                        expired.push(serde_json::json!({
                            "resource": id,
                            "machine": lock.machine,
                            "applied_at": at,
                        }));
                    }
                }
            }
        }
    }
    let _ = cutoff; // Duration comparison would need proper timestamp parsing

    if json {
        println!(
            "{}",
            serde_json::to_string_pretty(&expired).unwrap_or_else(|_| "[]".to_string())
        );
    } else {
        println!("Resources older than {}:\n", duration);
        if expired.is_empty() {
            println!("  {} No expired resources.", green("✓"));
        } else {
            for e in &expired {
                println!(
                    "  {} {} on {} (applied {})",
                    yellow("⏰"),
                    e["resource"].as_str().unwrap_or("?"),
                    e["machine"].as_str().unwrap_or("?"),
                    e["applied_at"].as_str().unwrap_or("?"),
                );
            }
        }
    }

    Ok(())
}

fn parse_duration_string(s: &str) -> Result<u64, String> {
    let s = s.trim();
    if s.is_empty() {
        return Err("empty duration string".to_string());
    }
    let (num_str, unit) = s.split_at(s.len() - 1);
    let num: u64 = num_str
        .parse()
        .map_err(|_| format!("invalid duration: {}", s))?;
    match unit {
        "s" => Ok(num),
        "m" => Ok(num * 60),
        "h" => Ok(num * 3600),
        "d" => Ok(num * 86400),
        _ => Err(format!(
            "unknown duration unit '{}'. Use s, m, h, or d",
            unit
        )),
    }
}

// ── FJ-391: validate --exhaustive ──

fn cmd_validate_exhaustive(file: &Path, json: bool) -> Result<(), String> {
    let config = parse_and_validate(file)?;
    let mut issues: Vec<String> = Vec::new();

    // Check all machine references in resources exist
    for (name, res) in &config.resources {
        let machine_name = match &res.machine {
            types::MachineTarget::Single(m) => Some(m.clone()),
            _ => None,
        };
        if let Some(ref m) = machine_name {
            if !config.machines.contains_key(m) {
                issues.push(format!(
                    "resource '{}' references unknown machine '{}'",
                    name, m
                ));
            }
        }

        // Check depends_on references exist
        for dep in &res.depends_on {
            if !config.resources.contains_key(dep) {
                issues.push(format!(
                    "resource '{}' depends on unknown resource '{}'",
                    name, dep
                ));
            }
        }
    }

    // Check params referenced in templates exist
    for (name, res) in &config.resources {
        if let Some(ref content) = res.content {
            let mut start = 0;
            while let Some(pos) = content[start..].find("{{params.") {
                let abs_pos = start + pos + 9;
                if let Some(end) = content[abs_pos..].find("}}") {
                    let key = &content[abs_pos..abs_pos + end];
                    if !config.params.contains_key(key) {
                        issues.push(format!(
                            "resource '{}' references unknown param '{}'",
                            name, key
                        ));
                    }
                    start = abs_pos + end + 2;
                } else {
                    break;
                }
            }
        }
    }

    // Check for orphaned params (defined but never used)
    for param_key in config.params.keys() {
        let yaml_str = serde_yaml_ng::to_string(&config).unwrap_or_default();
        let needle = format!("{{{{params.{}}}}}", param_key);
        if !yaml_str.contains(&needle) {
            issues.push(format!(
                "param '{}' is defined but never referenced",
                param_key
            ));
        }
    }

    if json {
        println!(
            "{{\"valid\":{},\"issues\":{},\"issue_count\":{}}}",
            issues.is_empty(),
            serde_json::to_string(&issues).unwrap_or_else(|_| "[]".to_string()),
            issues.len()
        );
    } else if issues.is_empty() {
        println!("{} Exhaustive validation passed", green("✓"));
    } else {
        println!(
            "{} Exhaustive validation found {} issue(s):",
            red("✗"),
            issues.len()
        );
        for issue in &issues {
            println!("  {} {}", red("•"), issue);
        }
    }
    if issues.is_empty() {
        Ok(())
    } else {
        Err(format!("{} validation issue(s) found", issues.len()))
    }
}

// ── FJ-392: status --count ──

fn cmd_status_count(state_dir: &Path, machine: Option<&str>, json: bool) -> Result<(), String> {
    let mut converged = 0usize;
    let mut failed = 0usize;
    let mut drifted = 0usize;
    let mut unknown = 0usize;

    if state_dir.exists() {
        let entries = std::fs::read_dir(state_dir).map_err(|e| e.to_string())?;
        for entry in entries.flatten() {
            let path = entry.path();
            if path.is_dir() {
                let m_name = path
                    .file_name()
                    .unwrap_or_default()
                    .to_string_lossy()
                    .to_string();
                if let Some(filter) = machine {
                    if m_name != filter {
                        continue;
                    }
                }
                if let Ok(Some(lock)) = state::load_lock(state_dir, &m_name) {
                    for rl in lock.resources.values() {
                        match rl.status {
                            types::ResourceStatus::Converged => converged += 1,
                            types::ResourceStatus::Failed => failed += 1,
                            types::ResourceStatus::Drifted => drifted += 1,
                            types::ResourceStatus::Unknown => unknown += 1,
                        }
                    }
                }
            }
        }
    }

    let total = converged + failed + drifted + unknown;
    if json {
        println!(
            "{{\"total\":{},\"converged\":{},\"failed\":{},\"drifted\":{},\"unknown\":{}}}",
            total, converged, failed, drifted, unknown
        );
    } else {
        println!("{}", bold("Resource Count by Status"));
        println!("  {} converged: {}", green("●"), converged);
        println!("  {} failed:    {}", red("●"), failed);
        println!("  {} drifted:   {}", yellow("●"), drifted);
        println!("  {} unknown:   {}", dim("●"), unknown);
        println!("  ─────────────");
        println!("  total:      {}", total);
    }
    Ok(())
}

// ── FJ-394: graph --depth ──

fn cmd_graph_depth(file: &Path, format: &str, max_depth: usize) -> Result<(), String> {
    let config = parse_and_validate(file)?;
    let order = resolver::build_execution_order(&config)?;

    // Build adjacency and compute depths via BFS from roots
    let mut children: std::collections::HashMap<&str, Vec<&str>> = std::collections::HashMap::new();
    let mut has_parent = std::collections::HashSet::new();
    for (name, res) in &config.resources {
        for dep in &res.depends_on {
            children
                .entry(dep.as_str())
                .or_default()
                .push(name.as_str());
            has_parent.insert(name.as_str());
        }
    }

    // BFS from roots to compute depth
    let mut depth_map: std::collections::HashMap<&str, usize> = std::collections::HashMap::new();
    let mut queue = std::collections::VecDeque::new();
    for name in &order {
        if !has_parent.contains(name.as_str()) {
            depth_map.insert(name.as_str(), 0);
            queue.push_back(name.as_str());
        }
    }
    while let Some(node) = queue.pop_front() {
        let d = depth_map[node];
        if let Some(kids) = children.get(node) {
            for &kid in kids {
                if !depth_map.contains_key(kid) {
                    depth_map.insert(kid, d + 1);
                    queue.push_back(kid);
                }
            }
        }
    }

    // Filter to depth <= max_depth
    let included: std::collections::HashSet<&str> = depth_map
        .iter()
        .filter(|(_, &d)| d <= max_depth)
        .map(|(&n, _)| n)
        .collect();

    if format == "mermaid" {
        println!("graph TD");
        for (name, res) in &config.resources {
            if !included.contains(name.as_str()) {
                continue;
            }
            for dep in &res.depends_on {
                if included.contains(dep.as_str()) {
                    println!("  {} --> {}", dep, name);
                }
            }
        }
        // Isolated nodes at valid depth
        for name in &order {
            if included.contains(name.as_str()) {
                let res = &config.resources[name];
                if res.depends_on.is_empty() && !children.contains_key(name.as_str()) {
                    println!("  {}", name);
                }
            }
        }
    } else {
        println!("digraph G {{");
        for (name, res) in &config.resources {
            if !included.contains(name.as_str()) {
                continue;
            }
            for dep in &res.depends_on {
                if included.contains(dep.as_str()) {
                    println!("  \"{}\" -> \"{}\"", dep, name);
                }
            }
        }
        println!("}}");
    }
    Ok(())
}

// ── FJ-395: lock compact ──

fn cmd_lock_compact(state_dir: &Path, yes: bool, json: bool) -> Result<(), String> {
    if !state_dir.exists() {
        return Err(format!(
            "state directory not found: {}",
            state_dir.display()
        ));
    }

    let mut total_removed = 0usize;
    let mut machines_compacted = Vec::new();

    let entries = std::fs::read_dir(state_dir).map_err(|e| e.to_string())?;
    for entry in entries.flatten() {
        let path = entry.path();
        if path.is_dir() {
            let m_name = path
                .file_name()
                .unwrap_or_default()
                .to_string_lossy()
                .to_string();
            // Check for event log — compacting means removing old events
            let log_path = path.join("events.jsonl");
            if log_path.exists() {
                let content = std::fs::read_to_string(&log_path).unwrap_or_default();
                let lines: Vec<&str> = content.lines().collect();
                if lines.len() > 1 {
                    let removed = lines.len() - 1;
                    if yes {
                        // Keep only the last event line
                        let last = lines.last().unwrap_or(&"");
                        std::fs::write(&log_path, format!("{}\n", last))
                            .map_err(|e| e.to_string())?;
                    }
                    total_removed += removed;
                    machines_compacted.push((m_name, removed));
                }
            }
        }
    }

    if json {
        let entries: Vec<String> = machines_compacted
            .iter()
            .map(|(m, n)| format!("{{\"machine\":\"{}\",\"removed\":{}}}", m, n))
            .collect();
        println!(
            "{{\"compacted\":{},\"total_removed\":{},\"dry_run\":{},\"machines\":[{}]}}",
            yes,
            total_removed,
            !yes,
            entries.join(",")
        );
    } else if machines_compacted.is_empty() {
        println!("Nothing to compact — event logs are already minimal.");
    } else if yes {
        println!("{} Compacted {} event(s):", green("✓"), total_removed);
        for (m, n) in &machines_compacted {
            println!("  {} — {} old event(s) removed", m, n);
        }
    } else {
        println!("Dry run — would compact {} event(s):", total_removed);
        for (m, n) in &machines_compacted {
            println!("  {} — {} old event(s)", m, n);
        }
        println!("\nRun with {} to compact.", bold("--yes"));
    }
    Ok(())
}

// ── FJ-397: status --format ──

fn cmd_status_format(state_dir: &Path, machine: Option<&str>, fmt: &str) -> Result<(), String> {
    match fmt {
        "json" => {
            let mut all = Vec::new();
            if state_dir.exists() {
                let entries = std::fs::read_dir(state_dir).map_err(|e| e.to_string())?;
                for entry in entries.flatten() {
                    let path = entry.path();
                    if path.is_dir() {
                        let m_name = path
                            .file_name()
                            .unwrap_or_default()
                            .to_string_lossy()
                            .to_string();
                        if let Some(filter) = machine {
                            if m_name != filter {
                                continue;
                            }
                        }
                        if let Ok(Some(lock)) = state::load_lock(state_dir, &m_name) {
                            for (name, rl) in &lock.resources {
                                all.push(format!(
                                    "{{\"machine\":\"{}\",\"resource\":\"{}\",\"status\":\"{:?}\",\"applied_at\":{}}}",
                                    m_name,
                                    name,
                                    rl.status,
                                    rl.applied_at
                                        .as_deref()
                                        .map(|s| format!("\"{}\"", s))
                                        .unwrap_or_else(|| "null".to_string()),
                                ));
                            }
                        }
                    }
                }
            }
            println!("[{}]", all.join(","));
        }
        "csv" => {
            println!("machine,resource,status,applied_at");
            if state_dir.exists() {
                let entries = std::fs::read_dir(state_dir).map_err(|e| e.to_string())?;
                for entry in entries.flatten() {
                    let path = entry.path();
                    if path.is_dir() {
                        let m_name = path
                            .file_name()
                            .unwrap_or_default()
                            .to_string_lossy()
                            .to_string();
                        if let Some(filter) = machine {
                            if m_name != filter {
                                continue;
                            }
                        }
                        if let Ok(Some(lock)) = state::load_lock(state_dir, &m_name) {
                            for (name, rl) in &lock.resources {
                                println!(
                                    "{},{},{:?},{}",
                                    m_name,
                                    name,
                                    rl.status,
                                    rl.applied_at.as_deref().unwrap_or(""),
                                );
                            }
                        }
                    }
                }
            }
        }
        "table" => {
            return cmd_status(state_dir, machine, false, None, false);
        }
        _ => {
            return Err(format!("unknown format '{}'. Use table, json, or csv", fmt));
        }
    }
    Ok(())
}

// ── FJ-401: validate --policy-file ──

fn cmd_validate_policy_file(file: &Path, policy_file: &Path, json: bool) -> Result<(), String> {
    let config = parse_and_validate(file)?;
    let policy_content = std::fs::read_to_string(policy_file).map_err(|e| {
        format!(
            "Failed to read policy file {}: {}",
            policy_file.display(),
            e
        )
    })?;
    let policy: serde_yaml_ng::Value = serde_yaml_ng::from_str(&policy_content)
        .map_err(|e| format!("Failed to parse policy file: {}", e))?;

    let mut violations: Vec<String> = Vec::new();

    // Check policy rules
    if let Some(rules) = policy.get("rules").and_then(|v| v.as_sequence()) {
        for rule in rules {
            let rule_name = rule
                .get("name")
                .and_then(|v| v.as_str())
                .unwrap_or("unnamed");
            let rule_type = rule.get("check").and_then(|v| v.as_str()).unwrap_or("");

            match rule_type {
                "no_root_owner" => {
                    for (name, res) in &config.resources {
                        if res.owner.as_deref() == Some("root") {
                            violations.push(format!(
                                "[{}] resource '{}' has owner 'root'",
                                rule_name, name
                            ));
                        }
                    }
                }
                "require_tags" => {
                    for (name, res) in &config.resources {
                        if res.tags.is_empty() {
                            violations
                                .push(format!("[{}] resource '{}' has no tags", rule_name, name));
                        }
                    }
                }
                "require_depends_on" => {
                    for (name, res) in &config.resources {
                        if res.depends_on.is_empty()
                            && res.resource_type != types::ResourceType::Package
                        {
                            violations.push(format!(
                                "[{}] resource '{}' has no depends_on",
                                rule_name, name
                            ));
                        }
                    }
                }
                _ => {
                    violations.push(format!("unknown policy check: '{}'", rule_type));
                }
            }
        }
    }

    if json {
        println!(
            "{{\"valid\":{},\"violations\":{},\"count\":{}}}",
            violations.is_empty(),
            serde_json::to_string(&violations).unwrap_or_else(|_| "[]".to_string()),
            violations.len()
        );
    } else if violations.is_empty() {
        println!("{} Policy validation passed", green("✓"));
    } else {
        println!(
            "{} Policy validation found {} violation(s):",
            red("✗"),
            violations.len()
        );
        for v in &violations {
            println!("  {} {}", red("•"), v);
        }
    }
    if violations.is_empty() {
        Ok(())
    } else {
        Err(format!("{} policy violation(s) found", violations.len()))
    }
}

// ── FJ-402: status --anomalies ──

fn cmd_status_anomalies(state_dir: &Path, machine: Option<&str>, json: bool) -> Result<(), String> {
    let mut anomalies: Vec<(String, String, String)> = Vec::new(); // (machine, resource, issue)

    if state_dir.exists() {
        let entries = std::fs::read_dir(state_dir).map_err(|e| e.to_string())?;
        for entry in entries.flatten() {
            let path = entry.path();
            if path.is_dir() {
                let m_name = path
                    .file_name()
                    .unwrap_or_default()
                    .to_string_lossy()
                    .to_string();
                if let Some(filter) = machine {
                    if m_name != filter {
                        continue;
                    }
                }
                if let Ok(Some(lock)) = state::load_lock(state_dir, &m_name) {
                    for (name, rl) in &lock.resources {
                        // Detect anomalies: failed status, missing applied_at, drifted
                        match rl.status {
                            types::ResourceStatus::Failed => {
                                anomalies.push((
                                    m_name.clone(),
                                    name.clone(),
                                    "status is Failed".to_string(),
                                ));
                            }
                            types::ResourceStatus::Drifted => {
                                anomalies.push((
                                    m_name.clone(),
                                    name.clone(),
                                    "status is Drifted".to_string(),
                                ));
                            }
                            _ => {}
                        }
                        if rl.applied_at.is_none() {
                            anomalies.push((
                                m_name.clone(),
                                name.clone(),
                                "missing applied_at timestamp".to_string(),
                            ));
                        }
                    }
                }
            }
        }
    }

    if json {
        let entries: Vec<String> = anomalies
            .iter()
            .map(|(m, r, issue)| {
                format!(
                    "{{\"machine\":\"{}\",\"resource\":\"{}\",\"issue\":\"{}\"}}",
                    m, r, issue
                )
            })
            .collect();
        println!("[{}]", entries.join(","));
    } else if anomalies.is_empty() {
        println!("{} No anomalies detected", green("✓"));
    } else {
        println!("{} {} anomalie(s) detected:", yellow("⚠"), anomalies.len());
        for (m, r, issue) in &anomalies {
            println!("  {} {}/{} — {}", red("•"), m, r, issue);
        }
    }
    Ok(())
}

// ── FJ-404: graph --cluster ──

fn cmd_graph_cluster(file: &Path, format: &str) -> Result<(), String> {
    let config = parse_and_validate(file)?;

    // Group resources by machine
    let mut by_machine: std::collections::HashMap<String, Vec<String>> =
        std::collections::HashMap::new();
    for (name, res) in &config.resources {
        let m = match &res.machine {
            types::MachineTarget::Single(m) => m.clone(),
            types::MachineTarget::Multiple(ms) => {
                ms.first().cloned().unwrap_or_else(|| "unknown".to_string())
            }
        };
        by_machine.entry(m).or_default().push(name.clone());
    }

    if format == "mermaid" {
        println!("graph TD");
        for (machine, resources) in &by_machine {
            println!("  subgraph {}", machine);
            for name in resources {
                println!("    {}", name);
            }
            println!("  end");
        }
        // Edges
        for (name, res) in &config.resources {
            for dep in &res.depends_on {
                println!("  {} --> {}", dep, name);
            }
        }
    } else {
        println!("digraph G {{");
        for (machine, resources) in &by_machine {
            println!("  subgraph cluster_{} {{", machine.replace('-', "_"));
            println!("    label=\"{}\";", machine);
            for name in resources {
                println!("    \"{}\";", name);
            }
            println!("  }}");
        }
        for (name, res) in &config.resources {
            for dep in &res.depends_on {
                println!("  \"{}\" -> \"{}\";", dep, name);
            }
        }
        println!("}}");
    }
    Ok(())
}

// ── FJ-405: lock verify ──

fn cmd_lock_verify(state_dir: &Path, json: bool) -> Result<(), String> {
    if !state_dir.exists() {
        return Err(format!(
            "state directory not found: {}",
            state_dir.display()
        ));
    }

    let mut verified = 0usize;
    let mut corrupt = 0usize;
    let mut machines_checked = Vec::new();

    let entries = std::fs::read_dir(state_dir).map_err(|e| e.to_string())?;
    for entry in entries.flatten() {
        let path = entry.path();
        if path.is_dir() {
            let m_name = path
                .file_name()
                .unwrap_or_default()
                .to_string_lossy()
                .to_string();
            let lock_path = path.join("lock.yaml");
            if lock_path.exists() {
                match state::load_lock(state_dir, &m_name) {
                    Ok(Some(lock)) => {
                        // Verify each resource hash is present and non-empty
                        let mut ok = true;
                        for (name, rl) in &lock.resources {
                            if rl.hash.is_empty() {
                                ok = false;
                                corrupt += 1;
                                machines_checked.push((
                                    m_name.clone(),
                                    name.clone(),
                                    "empty hash".to_string(),
                                ));
                            }
                        }
                        if ok {
                            verified += lock.resources.len();
                            machines_checked.push((
                                m_name.clone(),
                                String::new(),
                                format!("{} resources verified", lock.resources.len()),
                            ));
                        }
                    }
                    Ok(None) => {
                        machines_checked.push((
                            m_name.clone(),
                            String::new(),
                            "no lock data".to_string(),
                        ));
                    }
                    Err(e) => {
                        corrupt += 1;
                        machines_checked.push((
                            m_name.clone(),
                            String::new(),
                            format!("corrupt: {}", e),
                        ));
                    }
                }
            }
        }
    }

    if json {
        println!(
            "{{\"verified\":{},\"corrupt\":{},\"ok\":{}}}",
            verified,
            corrupt,
            corrupt == 0
        );
    } else if corrupt == 0 {
        println!(
            "{} Lock integrity verified — {} resource(s) checked",
            green("✓"),
            verified
        );
    } else {
        println!(
            "{} Lock integrity check found {} issue(s):",
            red("✗"),
            corrupt
        );
        for (m, r, issue) in &machines_checked {
            if !r.is_empty() {
                println!("  {} {}/{} — {}", red("•"), m, r, issue);
            } else if issue.contains("corrupt") {
                println!("  {} {} — {}", red("•"), m, issue);
            }
        }
    }
    if corrupt == 0 {
        Ok(())
    } else {
        Err(format!("{} lock integrity issue(s)", corrupt))
    }
}

// ── FJ-407: status --diff-from ──

fn cmd_status_diff_from(state_dir: &Path, snapshot_name: &str, json: bool) -> Result<(), String> {
    // Find snapshot directory
    let snap_dir = state_dir.join(".snapshots").join(snapshot_name);
    if !snap_dir.exists() {
        return Err(format!("snapshot '{}' not found", snapshot_name));
    }

    let mut diffs: Vec<(String, String, String)> = Vec::new(); // (machine, resource, change)

    // Load current state
    if state_dir.exists() {
        let entries = std::fs::read_dir(state_dir).map_err(|e| e.to_string())?;
        for entry in entries.flatten() {
            let path = entry.path();
            if path.is_dir() {
                let m_name = path
                    .file_name()
                    .unwrap_or_default()
                    .to_string_lossy()
                    .to_string();
                if m_name.starts_with('.') {
                    continue;
                }

                let current = state::load_lock(state_dir, &m_name).ok().flatten();
                let snapshot = state::load_lock(&snap_dir, &m_name).ok().flatten();

                match (current, snapshot) {
                    (Some(cur), Some(snap)) => {
                        // Compare resources
                        for (name, cur_rl) in &cur.resources {
                            match snap.resources.get(name) {
                                Some(snap_rl) => {
                                    if cur_rl.hash != snap_rl.hash {
                                        diffs.push((
                                            m_name.clone(),
                                            name.clone(),
                                            "modified".to_string(),
                                        ));
                                    }
                                }
                                None => {
                                    diffs.push((m_name.clone(), name.clone(), "added".to_string()));
                                }
                            }
                        }
                        for name in snap.resources.keys() {
                            if !cur.resources.contains_key(name) {
                                diffs.push((m_name.clone(), name.clone(), "removed".to_string()));
                            }
                        }
                    }
                    (Some(cur), None) => {
                        for name in cur.resources.keys() {
                            diffs.push((m_name.clone(), name.clone(), "added".to_string()));
                        }
                    }
                    (None, Some(snap)) => {
                        for name in snap.resources.keys() {
                            diffs.push((m_name.clone(), name.clone(), "removed".to_string()));
                        }
                    }
                    (None, None) => {}
                }
            }
        }
    }

    if json {
        let entries: Vec<String> = diffs
            .iter()
            .map(|(m, r, change)| {
                format!(
                    "{{\"machine\":\"{}\",\"resource\":\"{}\",\"change\":\"{}\"}}",
                    m, r, change
                )
            })
            .collect();
        println!("[{}]", entries.join(","));
    } else if diffs.is_empty() {
        println!(
            "{} No changes since snapshot '{}'",
            green("✓"),
            snapshot_name
        );
    } else {
        println!("Changes since snapshot '{}':", snapshot_name);
        for (m, r, change) in &diffs {
            let prefix = match change.as_str() {
                "added" => green("+"),
                "removed" => red("-"),
                "modified" => yellow("~"),
                _ => dim("?"),
            };
            println!("  {} {}/{}", prefix, m, r);
        }
    }
    Ok(())
}

// ── FJ-411: validate --check-connectivity ──

fn cmd_validate_connectivity(file: &Path, json: bool) -> Result<(), String> {
    let config = parse_and_validate(file)?;
    let mut results: Vec<(String, String, bool)> = Vec::new(); // (machine, addr, reachable)

    for (name, machine) in &config.machines {
        let addr = &machine.addr;
        // Quick TCP check on port 22 (SSH)
        let reachable = std::net::TcpStream::connect_timeout(
            &format!("{}:22", addr)
                .parse()
                .unwrap_or_else(|_| std::net::SocketAddr::from(([127, 0, 0, 1], 22))),
            std::time::Duration::from_secs(3),
        )
        .is_ok();
        results.push((name.clone(), addr.clone(), reachable));
    }

    if json {
        let entries: Vec<String> = results
            .iter()
            .map(|(name, addr, ok)| {
                format!(
                    "{{\"machine\":\"{}\",\"addr\":\"{}\",\"reachable\":{}}}",
                    name, addr, ok
                )
            })
            .collect();
        println!("[{}]", entries.join(","));
    } else {
        println!("{}", bold("SSH Connectivity Check"));
        for (name, addr, ok) in &results {
            let status = if *ok {
                green("✓ reachable")
            } else {
                red("✗ unreachable")
            };
            println!("  {} ({}) — {}", name, addr, status);
        }
    }
    Ok(())
}

// ── FJ-412: status --resources-by-type ──

fn cmd_status_resources_by_type(
    state_dir: &Path,
    machine: Option<&str>,
    json: bool,
) -> Result<(), String> {
    let mut by_type: std::collections::HashMap<String, Vec<(String, String, String)>> =
        std::collections::HashMap::new(); // type -> [(machine, name, status)]

    if state_dir.exists() {
        let entries = std::fs::read_dir(state_dir).map_err(|e| e.to_string())?;
        for entry in entries.flatten() {
            let path = entry.path();
            if path.is_dir() {
                let m_name = path
                    .file_name()
                    .unwrap_or_default()
                    .to_string_lossy()
                    .to_string();
                if let Some(filter) = machine {
                    if m_name != filter {
                        continue;
                    }
                }
                if let Ok(Some(lock)) = state::load_lock(state_dir, &m_name) {
                    for (name, rl) in &lock.resources {
                        let rtype = format!("{:?}", rl.resource_type);
                        by_type.entry(rtype).or_default().push((
                            m_name.clone(),
                            name.clone(),
                            format!("{:?}", rl.status),
                        ));
                    }
                }
            }
        }
    }

    if json {
        let entries: Vec<String> = by_type
            .iter()
            .map(|(t, resources)| {
                let items: Vec<String> = resources
                    .iter()
                    .map(|(m, n, s)| {
                        format!(
                            "{{\"machine\":\"{}\",\"resource\":\"{}\",\"status\":\"{}\"}}",
                            m, n, s
                        )
                    })
                    .collect();
                format!("\"{}\":[{}]", t, items.join(","))
            })
            .collect();
        println!("{{{}}}", entries.join(","));
    } else {
        for (rtype, resources) in &by_type {
            println!("{} ({}):", bold(rtype), resources.len());
            for (m, n, s) in resources {
                println!("  {}/{} — {}", m, n, s);
            }
        }
    }
    Ok(())
}

// ── FJ-414: graph --orphans ──

fn cmd_graph_orphans(file: &Path) -> Result<(), String> {
    let config = parse_and_validate(file)?;

    // Build who-depends-on-whom
    let mut has_dependents = std::collections::HashSet::new();
    let mut has_deps = std::collections::HashSet::new();
    for (name, res) in &config.resources {
        for dep in &res.depends_on {
            has_dependents.insert(dep.clone());
            has_deps.insert(name.clone());
        }
    }

    let mut orphans = Vec::new();
    for name in config.resources.keys() {
        if !has_dependents.contains(name) && !has_deps.contains(name) {
            orphans.push(name.clone());
        }
    }

    if orphans.is_empty() {
        println!("{} No orphan resources found", green("✓"));
    } else {
        println!(
            "{} {} orphan resource(s) (no deps, no dependents):",
            yellow("⚠"),
            orphans.len()
        );
        for name in &orphans {
            let res = &config.resources[name];
            println!("  {} (type: {:?})", name, res.resource_type);
        }
    }
    Ok(())
}

// ── FJ-415: lock export ──

fn cmd_lock_export(state_dir: &Path, fmt: &str, machine: Option<&str>) -> Result<(), String> {
    let mut all_resources: Vec<(String, String, String, String)> = Vec::new(); // (machine, name, status, hash)

    if state_dir.exists() {
        let entries = std::fs::read_dir(state_dir).map_err(|e| e.to_string())?;
        for entry in entries.flatten() {
            let path = entry.path();
            if path.is_dir() {
                let m_name = path
                    .file_name()
                    .unwrap_or_default()
                    .to_string_lossy()
                    .to_string();
                if let Some(filter) = machine {
                    if m_name != filter {
                        continue;
                    }
                }
                if let Ok(Some(lock)) = state::load_lock(state_dir, &m_name) {
                    for (name, rl) in &lock.resources {
                        all_resources.push((
                            m_name.clone(),
                            name.clone(),
                            format!("{:?}", rl.status),
                            rl.hash.clone(),
                        ));
                    }
                }
            }
        }
    }

    match fmt {
        "json" => {
            let entries: Vec<String> = all_resources
                .iter()
                .map(|(m, n, s, h)| {
                    format!(
                        "{{\"machine\":\"{}\",\"resource\":\"{}\",\"status\":\"{}\",\"hash\":\"{}\"}}",
                        m, n, s, h
                    )
                })
                .collect();
            println!("[{}]", entries.join(","));
        }
        "csv" => {
            println!("machine,resource,status,hash");
            for (m, n, s, h) in &all_resources {
                println!("{},{},{},{}", m, n, s, h);
            }
        }
        "yaml" => {
            println!("resources:");
            for (m, n, s, h) in &all_resources {
                println!("  - machine: {}", m);
                println!("    resource: {}", n);
                println!("    status: {}", s);
                println!("    hash: {}", h);
            }
        }
        _ => {
            return Err(format!("unknown format '{}'. Use json, csv, or yaml", fmt));
        }
    }
    Ok(())
}

// ── FJ-417: status --machines-only ──

fn cmd_status_machines_only(
    state_dir: &Path,
    machine: Option<&str>,
    json: bool,
) -> Result<(), String> {
    let mut machines: Vec<(String, usize, usize, usize)> = Vec::new(); // (name, total, converged, failed)

    if state_dir.exists() {
        let entries = std::fs::read_dir(state_dir).map_err(|e| e.to_string())?;
        for entry in entries.flatten() {
            let path = entry.path();
            if path.is_dir() {
                let m_name = path
                    .file_name()
                    .unwrap_or_default()
                    .to_string_lossy()
                    .to_string();
                if m_name.starts_with('.') {
                    continue;
                }
                if let Some(filter) = machine {
                    if m_name != filter {
                        continue;
                    }
                }
                if let Ok(Some(lock)) = state::load_lock(state_dir, &m_name) {
                    let total = lock.resources.len();
                    let converged = lock
                        .resources
                        .values()
                        .filter(|r| r.status == types::ResourceStatus::Converged)
                        .count();
                    let failed = lock
                        .resources
                        .values()
                        .filter(|r| r.status == types::ResourceStatus::Failed)
                        .count();
                    machines.push((m_name, total, converged, failed));
                }
            }
        }
    }

    if json {
        let entries: Vec<String> = machines
            .iter()
            .map(|(m, t, c, f)| {
                format!(
                    "{{\"machine\":\"{}\",\"total\":{},\"converged\":{},\"failed\":{}}}",
                    m, t, c, f
                )
            })
            .collect();
        println!("[{}]", entries.join(","));
    } else {
        println!("{}", bold("Machine Summary"));
        for (m, total, converged, failed) in &machines {
            let status = if *failed > 0 {
                red("DEGRADED")
            } else {
                green("HEALTHY")
            };
            println!(
                "  {} — {} ({} resources, {} converged, {} failed)",
                m, status, total, converged, failed
            );
        }
        if machines.is_empty() {
            println!("  {}", dim("No machines found in state"));
        }
    }
    Ok(())
}

// ── FJ-421: validate --check-templates ──

fn cmd_validate_check_templates(file: &Path, json: bool) -> Result<(), String> {
    let config = parse_and_validate(file)?;
    let mut unresolved: Vec<(String, String)> = Vec::new(); // (resource, variable)

    for (name, res) in &config.resources {
        // Check content field for unresolved templates
        if let Some(ref content) = res.content {
            let mut start = 0;
            while let Some(pos) = content[start..].find("{{") {
                let abs_pos = start + pos + 2;
                if let Some(end) = content[abs_pos..].find("}}") {
                    let var = content[abs_pos..abs_pos + end].trim();
                    // Check if it resolves — params.KEY should exist
                    if let Some(stripped) = var.strip_prefix("params.") {
                        if !config.params.contains_key(stripped) {
                            unresolved.push((name.clone(), var.to_string()));
                        }
                    }
                    start = abs_pos + end + 2;
                } else {
                    break;
                }
            }
        }
        // Check path field
        if let Some(ref path_str) = res.path {
            let mut start = 0;
            while let Some(pos) = path_str[start..].find("{{") {
                let abs_pos = start + pos + 2;
                if let Some(end) = path_str[abs_pos..].find("}}") {
                    let var = path_str[abs_pos..abs_pos + end].trim();
                    if let Some(stripped) = var.strip_prefix("params.") {
                        if !config.params.contains_key(stripped) {
                            unresolved.push((name.clone(), var.to_string()));
                        }
                    }
                    start = abs_pos + end + 2;
                } else {
                    break;
                }
            }
        }
    }

    if json {
        let entries: Vec<String> = unresolved
            .iter()
            .map(|(r, v)| format!("{{\"resource\":\"{}\",\"variable\":\"{}\"}}", r, v))
            .collect();
        println!(
            "{{\"valid\":{},\"unresolved\":[{}],\"count\":{}}}",
            unresolved.is_empty(),
            entries.join(","),
            unresolved.len()
        );
    } else if unresolved.is_empty() {
        println!("{} All template variables resolve", green("✓"));
    } else {
        println!(
            "{} {} unresolved template variable(s):",
            red("✗"),
            unresolved.len()
        );
        for (r, v) in &unresolved {
            println!("  {} resource '{}': {{{{{}}}}}", red("•"), r, v);
        }
    }
    if unresolved.is_empty() {
        Ok(())
    } else {
        Err(format!(
            "{} unresolved template variable(s)",
            unresolved.len()
        ))
    }
}

// ── FJ-422: status --stale-resources ──

fn cmd_status_stale_resources(
    state_dir: &Path,
    machine: Option<&str>,
    json: bool,
) -> Result<(), String> {
    let mut stale: Vec<(String, String, String)> = Vec::new(); // (machine, resource, applied_at)

    if state_dir.exists() {
        let entries = std::fs::read_dir(state_dir).map_err(|e| e.to_string())?;
        for entry in entries.flatten() {
            let path = entry.path();
            if path.is_dir() {
                let m_name = path
                    .file_name()
                    .unwrap_or_default()
                    .to_string_lossy()
                    .to_string();
                if m_name.starts_with('.') {
                    continue;
                }
                if let Some(filter) = machine {
                    if m_name != filter {
                        continue;
                    }
                }
                if let Ok(Some(lock)) = state::load_lock(state_dir, &m_name) {
                    for (name, rl) in &lock.resources {
                        // Resources with no applied_at or very old timestamps
                        if rl.applied_at.is_none() {
                            stale.push((m_name.clone(), name.clone(), "never".to_string()));
                        }
                    }
                }
            }
        }
    }

    if json {
        let entries: Vec<String> = stale
            .iter()
            .map(|(m, r, at)| {
                format!(
                    "{{\"machine\":\"{}\",\"resource\":\"{}\",\"last_applied\":\"{}\"}}",
                    m, r, at
                )
            })
            .collect();
        println!("[{}]", entries.join(","));
    } else if stale.is_empty() {
        println!("{} No stale resources found", green("✓"));
    } else {
        println!(
            "{} {} stale resource(s) (never applied):",
            yellow("⚠"),
            stale.len()
        );
        for (m, r, at) in &stale {
            println!("  {} {}/{} — last applied: {}", yellow("●"), m, r, at);
        }
    }
    Ok(())
}

// ── FJ-424: graph --stats ──

fn cmd_graph_stats(file: &Path) -> Result<(), String> {
    let config = parse_and_validate(file)?;
    let order = resolver::build_execution_order(&config)?;

    let nodes = config.resources.len();
    let mut edges = 0usize;
    let mut max_deps = 0usize;
    for res in config.resources.values() {
        edges += res.depends_on.len();
        max_deps = max_deps.max(res.depends_on.len());
    }

    // Compute depth via BFS
    let mut children: std::collections::HashMap<&str, Vec<&str>> = std::collections::HashMap::new();
    let mut has_parent = std::collections::HashSet::new();
    for (name, res) in &config.resources {
        for dep in &res.depends_on {
            children
                .entry(dep.as_str())
                .or_default()
                .push(name.as_str());
            has_parent.insert(name.as_str());
        }
    }
    let mut depth_map: std::collections::HashMap<&str, usize> = std::collections::HashMap::new();
    let mut queue = std::collections::VecDeque::new();
    for name in &order {
        if !has_parent.contains(name.as_str()) {
            depth_map.insert(name.as_str(), 0);
            queue.push_back(name.as_str());
        }
    }
    let mut max_depth = 0usize;
    while let Some(node) = queue.pop_front() {
        let d = depth_map[node];
        max_depth = max_depth.max(d);
        if let Some(kids) = children.get(node) {
            for &kid in kids {
                if !depth_map.contains_key(kid) {
                    depth_map.insert(kid, d + 1);
                    queue.push_back(kid);
                }
            }
        }
    }

    // Width = max nodes at any depth level
    let mut width_map: std::collections::HashMap<usize, usize> = std::collections::HashMap::new();
    for &d in depth_map.values() {
        *width_map.entry(d).or_insert(0) += 1;
    }
    let max_width = width_map.values().copied().max().unwrap_or(0);

    let roots = order
        .iter()
        .filter(|n| !has_parent.contains(n.as_str()))
        .count();
    let leaves = order
        .iter()
        .filter(|n| !children.contains_key(n.as_str()))
        .count();

    println!("{}", bold("Graph Statistics"));
    println!("  Nodes:     {}", nodes);
    println!("  Edges:     {}", edges);
    println!("  Depth:     {}", max_depth);
    println!("  Width:     {}", max_width);
    println!("  Roots:     {}", roots);
    println!("  Leaves:    {}", leaves);
    println!("  Max deps:  {}", max_deps);
    if nodes > 0 {
        println!("  Density:   {:.2}", edges as f64 / nodes as f64);
    }
    Ok(())
}

// ── FJ-425: lock gc ──

fn cmd_lock_gc(file: &Path, state_dir: &Path, yes: bool, json: bool) -> Result<(), String> {
    let config = parse_and_validate(file)?;
    let config_resources: std::collections::HashSet<&str> =
        config.resources.keys().map(|k| k.as_str()).collect();
    let mut orphaned: Vec<(String, String)> = Vec::new(); // (machine, resource)

    if state_dir.exists() {
        let entries = std::fs::read_dir(state_dir).map_err(|e| e.to_string())?;
        for entry in entries.flatten() {
            let path = entry.path();
            if path.is_dir() {
                let m_name = path
                    .file_name()
                    .unwrap_or_default()
                    .to_string_lossy()
                    .to_string();
                if m_name.starts_with('.') {
                    continue;
                }
                if let Ok(Some(lock)) = state::load_lock(state_dir, &m_name) {
                    for name in lock.resources.keys() {
                        if !config_resources.contains(name.as_str()) {
                            orphaned.push((m_name.clone(), name.clone()));
                        }
                    }
                }
            }
        }
    }

    if json {
        let entries: Vec<String> = orphaned
            .iter()
            .map(|(m, r)| format!("{{\"machine\":\"{}\",\"resource\":\"{}\"}}", m, r))
            .collect();
        println!(
            "{{\"orphaned\":{},\"dry_run\":{},\"entries\":[{}]}}",
            orphaned.len(),
            !yes,
            entries.join(",")
        );
    } else if orphaned.is_empty() {
        println!("{} No orphaned lock entries found", green("✓"));
    } else if yes {
        println!(
            "{} Would remove {} orphaned lock entries (removal not yet implemented — use lock-prune)",
            yellow("⚠"),
            orphaned.len()
        );
        for (m, r) in &orphaned {
            println!("  {} {}/{}", red("×"), m, r);
        }
    } else {
        println!("Dry run — found {} orphaned lock entries:", orphaned.len());
        for (m, r) in &orphaned {
            println!("  {} {}/{}", yellow("●"), m, r);
        }
        println!("\nRun with {} to remove.", bold("--yes"));
    }
    Ok(())
}

// ── FJ-427: status --health-threshold ──

fn cmd_status_health_threshold(
    state_dir: &Path,
    machine: Option<&str>,
    threshold: u32,
    json: bool,
) -> Result<(), String> {
    let mut total = 0usize;
    let mut converged = 0usize;

    if state_dir.exists() {
        let entries = std::fs::read_dir(state_dir).map_err(|e| e.to_string())?;
        for entry in entries.flatten() {
            let path = entry.path();
            if path.is_dir() {
                let m_name = path
                    .file_name()
                    .unwrap_or_default()
                    .to_string_lossy()
                    .to_string();
                if m_name.starts_with('.') {
                    continue;
                }
                if let Some(filter) = machine {
                    if m_name != filter {
                        continue;
                    }
                }
                if let Ok(Some(lock)) = state::load_lock(state_dir, &m_name) {
                    for rl in lock.resources.values() {
                        total += 1;
                        if rl.status == types::ResourceStatus::Converged {
                            converged += 1;
                        }
                    }
                }
            }
        }
    }

    let score = if total > 0 {
        (converged * 100 / total) as u32
    } else {
        100
    };
    let pass = score >= threshold;

    if json {
        println!(
            "{{\"score\":{},\"threshold\":{},\"pass\":{},\"total\":{},\"converged\":{}}}",
            score, threshold, pass, total, converged
        );
    } else {
        let status = if pass {
            green(&format!("PASS ({}%)", score))
        } else {
            red(&format!("FAIL ({}%)", score))
        };
        println!(
            "Health score: {} (threshold: {}%, {}/{} converged)",
            status, threshold, converged, total
        );
    }
    if pass {
        Ok(())
    } else {
        Err(format!(
            "Health score {}% below threshold {}%",
            score, threshold
        ))
    }
}

// ── FJ-431: validate --strict-deps ──

fn cmd_validate_strict_deps(file: &Path, json: bool) -> Result<(), String> {
    let config = parse_and_validate(file)?;
    let mut violations = Vec::new();

    // Collect resource names in declaration order
    let decl_order: Vec<String> = config.resources.keys().cloned().collect();
    let pos_map: std::collections::HashMap<&str, usize> = decl_order
        .iter()
        .enumerate()
        .map(|(i, name)| (name.as_str(), i))
        .collect();

    for (name, res) in &config.resources {
        let my_pos = pos_map.get(name.as_str()).copied().unwrap_or(0);
        for dep in &res.depends_on {
            if let Some(&dep_pos) = pos_map.get(dep.as_str()) {
                if dep_pos > my_pos {
                    violations.push(format!(
                        "{} depends on {} but {} is declared later",
                        name, dep, dep
                    ));
                }
            }
        }
    }

    if json {
        println!(
            "{{\"strict_deps\":true,\"violations\":{},\"ok\":{}}}",
            violations.len(),
            violations.is_empty()
        );
    } else if violations.is_empty() {
        println!(
            "{} All dependencies reference resources declared earlier.",
            green("✓")
        );
    } else {
        println!(
            "{} {} dependency ordering violation(s):",
            red("✗"),
            violations.len()
        );
        for v in &violations {
            println!("  - {}", v);
        }
    }
    if violations.is_empty() {
        Ok(())
    } else {
        Err(format!("{} strict-dep violations", violations.len()))
    }
}

