// ── FJ-435: lock diff ──

fn cmd_lock_diff(from: &Path, to: &Path, json: bool) -> Result<(), String> {
    // Load all locks from both state directories
    let load_all = |dir: &Path| -> Result<
        std::collections::HashMap<String, indexmap::IndexMap<String, types::ResourceLock>>,
        String,
    > {
        let mut result = std::collections::HashMap::new();
        if !dir.exists() {
            return Ok(result);
        }
        let entries = std::fs::read_dir(dir).map_err(|e| e.to_string())?;
        for entry in entries.flatten() {
            let path = entry.path();
            if path.is_dir() {
                let m_name = path
                    .file_name()
                    .unwrap_or_default()
                    .to_string_lossy()
                    .to_string();
                if m_name.starts_with('.') {
                    continue;
                }
                if let Ok(Some(lock)) = state::load_lock(dir, &m_name) {
                    result.insert(m_name, lock.resources);
                }
            }
        }
        Ok(result)
    };

    let left = load_all(from)?;
    let right = load_all(to)?;

    let mut diffs = Vec::new();

    // Find added/changed
    for (machine, resources) in &right {
        for (rname, rl) in resources {
            let left_hash = left
                .get(machine)
                .and_then(|r| r.get(rname))
                .map(|l| l.hash.as_str());
            match left_hash {
                None => diffs.push(format!("+ {}/{} (added)", machine, rname)),
                Some(h) if h != rl.hash => {
                    diffs.push(format!("~ {}/{} (changed)", machine, rname));
                }
                _ => {}
            }
        }
    }

    // Find removed
    for (machine, resources) in &left {
        for (rname, _) in resources {
            if !right.get(machine).is_some_and(|r| r.contains_key(rname)) {
                diffs.push(format!("- {}/{} (removed)", machine, rname));
            }
        }
    }

    if json {
        let items: Vec<String> = diffs.iter().map(|d| format!("\"{}\"", d)).collect();
        println!(
            "{{\"diffs\":[{}],\"count\":{}}}",
            items.join(","),
            diffs.len()
        );
    } else if diffs.is_empty() {
        println!("{} No differences between lock files.", green("✓"));
    } else {
        println!("{} difference(s):", diffs.len());
        for d in &diffs {
            println!("  {}", d);
        }
    }
    Ok(())
}

// ── FJ-437: status --since ──

fn cmd_status_since(
    state_dir: &Path,
    machine: Option<&str>,
    duration: &str,
    json: bool,
) -> Result<(), String> {
    // Parse duration string like "1h", "7d", "30m"
    let seconds = parse_duration_secs(duration)?;
    let cutoff = std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .unwrap_or_default()
        .as_secs()
        .saturating_sub(seconds);

    let mut results = Vec::new();

    if state_dir.exists() {
        let entries = std::fs::read_dir(state_dir).map_err(|e| e.to_string())?;
        for entry in entries.flatten() {
            let path = entry.path();
            if path.is_dir() {
                let m_name = path
                    .file_name()
                    .unwrap_or_default()
                    .to_string_lossy()
                    .to_string();
                if m_name.starts_with('.') {
                    continue;
                }
                if let Some(filter) = machine {
                    if m_name != filter {
                        continue;
                    }
                }
                // Check lock file modification time
                let lock_path = path.join("lock.yaml");
                if let Ok(meta) = std::fs::metadata(&lock_path) {
                    if let Ok(modified) = meta.modified() {
                        let mod_secs = modified
                            .duration_since(std::time::UNIX_EPOCH)
                            .unwrap_or_default()
                            .as_secs();
                        if mod_secs >= cutoff {
                            if let Ok(Some(lock)) = state::load_lock(state_dir, &m_name) {
                                for (rname, rl) in &lock.resources {
                                    results.push((
                                        m_name.clone(),
                                        rname.clone(),
                                        format!("{:?}", rl.status),
                                    ));
                                }
                            }
                        }
                    }
                }
            }
        }
    }

    if json {
        let items: Vec<String> = results
            .iter()
            .map(|(m, r, s)| {
                format!(
                    "{{\"machine\":\"{}\",\"resource\":\"{}\",\"status\":\"{}\"}}",
                    m, r, s
                )
            })
            .collect();
        println!("[{}]", items.join(","));
    } else if results.is_empty() {
        println!("No resources changed within {}.", duration);
    } else {
        println!("{} resource(s) changed within {}:", results.len(), duration);
        for (m, r, s) in &results {
            println!("  {}/{}: {}", m, r, s);
        }
    }
    Ok(())
}

// ── FJ-441: validate --check-secrets ──

fn cmd_validate_check_secrets(file: &Path, json: bool) -> Result<(), String> {
    let content = std::fs::read_to_string(file).map_err(|e| e.to_string())?;
    let secret_patterns = [
        "password:",
        "secret:",
        "api_key:",
        "token:",
        "private_key:",
        "aws_secret",
        "AKIA", // AWS access key prefix
        "ghp_", // GitHub PAT
        "sk-",  // OpenAI/Stripe key prefix
    ];

    let mut findings = Vec::new();
    for (i, line) in content.lines().enumerate() {
        let trimmed = line.trim().to_lowercase();
        // Skip comment lines
        if trimmed.starts_with('#') {
            continue;
        }
        for pattern in &secret_patterns {
            if trimmed.contains(&pattern.to_lowercase()) {
                findings.push((i + 1, pattern.to_string(), line.trim().to_string()));
            }
        }
    }

    if json {
        let items: Vec<String> = findings
            .iter()
            .map(|(line, pat, _)| format!("{{\"line\":{},\"pattern\":\"{}\"}}", line, pat))
            .collect();
        let findings_json = format!("[{}]", items.join(","));
        println!(
            "{{\"check_secrets\":true,\"findings\":{},\"ok\":{}}}",
            findings_json,
            findings.is_empty()
        );
    } else if findings.is_empty() {
        println!("{} No hardcoded secrets detected.", green("✓"));
    } else {
        println!(
            "{} {} potential secret(s) detected:",
            red("✗"),
            findings.len()
        );
        for (line, pattern, text) in &findings {
            println!("  line {}: pattern '{}' in: {}", line, pattern, text);
        }
    }
    if findings.is_empty() {
        Ok(())
    } else {
        Err(format!("{} potential secrets found", findings.len()))
    }
}

// ── FJ-442: status --export ──

fn cmd_status_export(
    state_dir: &Path,
    machine: Option<&str>,
    output_path: &Path,
    json: bool,
) -> Result<(), String> {
    let mut entries = Vec::new();
    if state_dir.exists() {
        let dir_entries = std::fs::read_dir(state_dir).map_err(|e| e.to_string())?;
        for entry in dir_entries.flatten() {
            let path = entry.path();
            if path.is_dir() {
                let m_name = path
                    .file_name()
                    .unwrap_or_default()
                    .to_string_lossy()
                    .to_string();
                if m_name.starts_with('.') {
                    continue;
                }
                if let Some(filter) = machine {
                    if m_name != filter {
                        continue;
                    }
                }
                if let Ok(Some(lock)) = state::load_lock(state_dir, &m_name) {
                    for (rname, rl) in &lock.resources {
                        entries.push(format!(
                            "{{\"machine\":\"{}\",\"resource\":\"{}\",\"status\":\"{:?}\",\"hash\":\"{}\"}}",
                            m_name, rname, rl.status, rl.hash
                        ));
                    }
                }
            }
        }
    }

    let content = format!("[{}]", entries.join(",\n"));
    std::fs::write(output_path, &content).map_err(|e| e.to_string())?;

    if json {
        println!(
            "{{\"exported\":true,\"path\":\"{}\",\"entries\":{}}}",
            output_path.display(),
            entries.len()
        );
    } else {
        println!(
            "{} Exported {} entries to {}",
            green("✓"),
            entries.len(),
            output_path.display()
        );
    }
    Ok(())
}

// ── FJ-444: graph --highlight ──

fn cmd_graph_highlight(file: &Path, format: &str, resource: &str) -> Result<(), String> {
    let config = parse_and_validate(file)?;
    let order = resolver::build_execution_order(&config)?;

    // Collect transitive deps of the highlighted resource
    let mut highlighted = std::collections::HashSet::new();
    highlighted.insert(resource.to_string());

    // BFS to find all transitive deps
    let mut queue = vec![resource.to_string()];
    while let Some(current) = queue.pop() {
        if let Some(res) = config.resources.get(&current) {
            for dep in &res.depends_on {
                if highlighted.insert(dep.clone()) {
                    queue.push(dep.clone());
                }
            }
        }
    }

    if format == "dot" {
        println!("digraph {{");
        println!("  rankdir=LR;");
        for name in &order {
            if highlighted.contains(name) {
                println!("  \"{}\" [style=filled, fillcolor=yellow];", name);
            } else {
                println!("  \"{}\";", name);
            }
            if let Some(res) = config.resources.get(name) {
                for dep in &res.depends_on {
                    let style = if highlighted.contains(name) && highlighted.contains(dep) {
                        " [color=red, penwidth=2]"
                    } else {
                        ""
                    };
                    println!("  \"{}\" -> \"{}\"{};", name, dep, style);
                }
            }
        }
        println!("}}");
    } else {
        // Mermaid format
        println!("graph LR");
        for name in &order {
            if highlighted.contains(name) {
                println!("  {}[\"⚡ {}\"]", name, name);
                println!(
                    "  style {} fill:#ffeb3b,stroke:#f44336,stroke-width:2px",
                    name
                );
            }
            if let Some(res) = config.resources.get(name) {
                for dep in &res.depends_on {
                    if highlighted.contains(name) && highlighted.contains(dep) {
                        println!("  {} ==>|dep| {}", name, dep);
                    } else {
                        println!("  {} --> {}", name, dep);
                    }
                }
            }
        }
    }
    Ok(())
}

// ── FJ-445: lock merge ──

fn cmd_lock_merge(from: &Path, to: &Path, output: &Path, json: bool) -> Result<(), String> {
    // Load all locks from both directories
    let mut merged_count = 0usize;
    let mut conflict_count = 0usize;

    if !from.exists() && !to.exists() {
        return Err("Both state directories are empty".to_string());
    }

    // Collect all machine names from both dirs
    let mut machines = std::collections::HashSet::new();
    for dir in [from, to] {
        if dir.exists() {
            if let Ok(entries) = std::fs::read_dir(dir) {
                for entry in entries.flatten() {
                    let path = entry.path();
                    if path.is_dir() {
                        let name = path
                            .file_name()
                            .unwrap_or_default()
                            .to_string_lossy()
                            .to_string();
                        if !name.starts_with('.') {
                            machines.insert(name);
                        }
                    }
                }
            }
        }
    }

    // Create output dir
    std::fs::create_dir_all(output).map_err(|e| e.to_string())?;

    for m_name in &machines {
        let left = state::load_lock(from, m_name).ok().flatten();
        let right = state::load_lock(to, m_name).ok().flatten();

        match (left, right) {
            (Some(_left_lock), Some(right_lock)) => {
                // Right takes precedence on conflicts
                let out_dir = output.join(m_name);
                std::fs::create_dir_all(&out_dir).map_err(|e| e.to_string())?;
                let lock_path = out_dir.join("lock.yaml");
                let yaml = serde_yaml_ng::to_string(&right_lock).map_err(|e| e.to_string())?;
                std::fs::write(&lock_path, yaml).map_err(|e| e.to_string())?;
                conflict_count += 1;
                merged_count += 1;
            }
            (Some(lock), None) | (None, Some(lock)) => {
                let out_dir = output.join(m_name);
                std::fs::create_dir_all(&out_dir).map_err(|e| e.to_string())?;
                let lock_path = out_dir.join("lock.yaml");
                let yaml = serde_yaml_ng::to_string(&lock).map_err(|e| e.to_string())?;
                std::fs::write(&lock_path, yaml).map_err(|e| e.to_string())?;
                merged_count += 1;
            }
            (None, None) => {}
        }
    }

    if json {
        println!(
            "{{\"merged\":{},\"conflicts\":{},\"output\":\"{}\"}}",
            merged_count,
            conflict_count,
            output.display()
        );
    } else {
        println!(
            "{} Merged {} machine(s) ({} conflicts, right takes precedence) → {}",
            green("✓"),
            merged_count,
            conflict_count,
            output.display()
        );
    }
    Ok(())
}

// ── FJ-451: validate --check-idempotency ──

fn cmd_validate_check_idempotency(file: &Path, json: bool) -> Result<(), String> {
    let config = parse_and_validate(file)?;
    let order = resolver::build_execution_order(&config)?;

    // Check each resource type for idempotency markers
    let mut non_idempotent = Vec::new();
    for name in &order {
        if let Some(res) = config.resources.get(name) {
            let rt = format!("{:?}", res.resource_type);
            // Resources with no state field or unknown types may not be idempotent
            if rt == "Unknown" {
                non_idempotent.push(format!("{}: unknown resource type", name));
            }
        }
    }

    if json {
        println!(
            "{{\"check_idempotency\":true,\"issues\":{},\"ok\":{}}}",
            non_idempotent.len(),
            non_idempotent.is_empty()
        );
    } else if non_idempotent.is_empty() {
        println!(
            "{} All {} resources produce idempotent scripts.",
            green("✓"),
            order.len()
        );
    } else {
        println!(
            "{} {} potential idempotency issue(s):",
            red("✗"),
            non_idempotent.len()
        );
        for issue in &non_idempotent {
            println!("  - {}", issue);
        }
    }
    Ok(())
}

// ── FJ-452: status --compact ──

fn cmd_status_compact(state_dir: &Path, machine: Option<&str>, json: bool) -> Result<(), String> {
    if !state_dir.exists() {
        println!("No state directory found.");
        return Ok(());
    }
    let entries = std::fs::read_dir(state_dir).map_err(|e| e.to_string())?;
    let mut lines = Vec::new();
    for entry in entries.flatten() {
        let path = entry.path();
        if path.is_dir() {
            let m_name = path
                .file_name()
                .unwrap_or_default()
                .to_string_lossy()
                .to_string();
            if m_name.starts_with('.') {
                continue;
            }
            if let Some(filter) = machine {
                if m_name != filter {
                    continue;
                }
            }
            if let Ok(Some(lock)) = state::load_lock(state_dir, &m_name) {
                let total = lock.resources.len();
                let converged = lock
                    .resources
                    .values()
                    .filter(|rl| rl.status == types::ResourceStatus::Converged)
                    .count();
                let failed = lock
                    .resources
                    .values()
                    .filter(|rl| rl.status == types::ResourceStatus::Failed)
                    .count();
                if json {
                    lines.push(format!(
                        "{{\"machine\":\"{}\",\"total\":{},\"converged\":{},\"failed\":{}}}",
                        m_name, total, converged, failed
                    ));
                } else {
                    let status = if failed > 0 {
                        red(&format!("{}F", failed))
                    } else {
                        green("OK")
                    };
                    lines.push(format!(
                        "{}: {}/{} converged [{}]",
                        m_name, converged, total, status
                    ));
                }
            }
        }
    }
    for line in &lines {
        println!("{}", line);
    }
    Ok(())
}

// ── FJ-454: graph --prune ──

fn cmd_graph_prune(file: &Path, format: &str, resource: &str) -> Result<(), String> {
    let config = parse_and_validate(file)?;
    let order = resolver::build_execution_order(&config)?;

    // Collect subtree of resource to prune (resource + all transitive dependents)
    let mut pruned = std::collections::HashSet::new();
    pruned.insert(resource.to_string());

    // Find all resources that transitively depend on the pruned resource
    let mut changed = true;
    while changed {
        changed = false;
        for name in &order {
            if pruned.contains(name) {
                continue;
            }
            if let Some(res) = config.resources.get(name) {
                for dep in &res.depends_on {
                    if pruned.contains(dep) {
                        pruned.insert(name.clone());
                        changed = true;
                        break;
                    }
                }
            }
        }
    }

    let remaining: Vec<&String> = order.iter().filter(|n| !pruned.contains(*n)).collect();

    if format == "dot" {
        println!("digraph {{");
        println!("  rankdir=LR;");
        for name in &remaining {
            println!("  \"{}\";", name);
            if let Some(res) = config.resources.get(*name) {
                for dep in &res.depends_on {
                    if !pruned.contains(dep) {
                        println!("  \"{}\" -> \"{}\";", name, dep);
                    }
                }
            }
        }
        println!("}}");
    } else {
        println!("graph LR");
        for name in &remaining {
            if let Some(res) = config.resources.get(*name) {
                for dep in &res.depends_on {
                    if !pruned.contains(dep) {
                        println!("  {} --> {}", name, dep);
                    }
                }
            }
        }
    }

    println!(
        "\n{} Pruned {} and {} dependent(s)",
        dim("──"),
        resource,
        pruned.len() - 1
    );
    Ok(())
}

// ── FJ-455: lock rebase ──

fn cmd_lock_rebase(
    from: &Path,
    config_file: &Path,
    output: &Path,
    json: bool,
) -> Result<(), String> {
    let config = parse_and_validate(config_file)?;
    let config_resources: std::collections::HashSet<String> =
        config.resources.keys().cloned().collect();

    std::fs::create_dir_all(output).map_err(|e| e.to_string())?;

    let mut kept = 0usize;
    let mut dropped = 0usize;

    if from.exists() {
        let entries = std::fs::read_dir(from).map_err(|e| e.to_string())?;
        for entry in entries.flatten() {
            let path = entry.path();
            if path.is_dir() {
                let m_name = path
                    .file_name()
                    .unwrap_or_default()
                    .to_string_lossy()
                    .to_string();
                if m_name.starts_with('.') {
                    continue;
                }
                if let Ok(Some(mut lock)) = state::load_lock(from, &m_name) {
                    let before = lock.resources.len();
                    lock.resources
                        .retain(|name, _| config_resources.contains(name));
                    let after = lock.resources.len();
                    kept += after;
                    dropped += before - after;

                    let out_dir = output.join(&m_name);
                    std::fs::create_dir_all(&out_dir).map_err(|e| e.to_string())?;
                    let lock_path = out_dir.join("lock.yaml");
                    let yaml = serde_yaml_ng::to_string(&lock).map_err(|e| e.to_string())?;
                    std::fs::write(&lock_path, yaml).map_err(|e| e.to_string())?;
                }
            }
        }
    }

    if json {
        println!(
            "{{\"kept\":{},\"dropped\":{},\"output\":\"{}\"}}",
            kept,
            dropped,
            output.display()
        );
    } else {
        println!(
            "{} Rebased: {} resources kept, {} dropped → {}",
            green("✓"),
            kept,
            dropped,
            output.display()
        );
    }
    Ok(())
}

// ── FJ-457: status --alerts ──

fn cmd_status_alerts(state_dir: &Path, machine: Option<&str>, json: bool) -> Result<(), String> {
    let mut alerts = Vec::new();
    if state_dir.exists() {
        let entries = std::fs::read_dir(state_dir).map_err(|e| e.to_string())?;
        for entry in entries.flatten() {
            let path = entry.path();
            if path.is_dir() {
                let m_name = path
                    .file_name()
                    .unwrap_or_default()
                    .to_string_lossy()
                    .to_string();
                if m_name.starts_with('.') {
                    continue;
                }
                if let Some(filter) = machine {
                    if m_name != filter {
                        continue;
                    }
                }
                if let Ok(Some(lock)) = state::load_lock(state_dir, &m_name) {
                    for (rname, rl) in &lock.resources {
                        match rl.status {
                            types::ResourceStatus::Failed | types::ResourceStatus::Drifted => {
                                alerts.push((
                                    m_name.clone(),
                                    rname.clone(),
                                    format!("{:?}", rl.status),
                                ));
                            }
                            _ => {}
                        }
                    }
                }
            }
        }
    }

    if json {
        let items: Vec<String> = alerts
            .iter()
            .map(|(m, r, s)| {
                format!(
                    "{{\"machine\":\"{}\",\"resource\":\"{}\",\"status\":\"{}\"}}",
                    m, r, s
                )
            })
            .collect();
        println!("[{}]", items.join(","));
    } else if alerts.is_empty() {
        println!("{} No alerts — all resources healthy.", green("✓"));
    } else {
        println!("{} {} alert(s):", red("⚠"), alerts.len());
        for (m, r, s) in &alerts {
            println!("  {}/{}: {}", m, r, s);
        }
    }
    Ok(())
}

