        let yaml = r#"
version: "1.0"
name: test
machines: {}
resources: {}
"#;
        let mut config: types::ForjarConfig = serde_yaml_ng::from_str(yaml).unwrap();
        let overrides = vec!["env=production".to_string(), "port=8080".to_string()];
