    #[test]
    fn test_fj211_apply_with_env_file() {
        let dir = tempfile::tempdir().unwrap();
        let file = write_env_config(dir.path());
        let env = dir.path().join("test.env.yaml");
        std::fs::write(&env, "data_dir: /tmp/forjar-fj211-env\n").unwrap();
        let state = dir.path().join("state");
        std::fs::create_dir_all(&state).unwrap();

        cmd_apply(
            &file,
            &state,
            None,
            None,
            None,
            None, // no group filter
            false,
            true, // dry_run
            false,
            &[],
            false,
            None,
            false,
            false,
            Some(env.as_path()),
            None,  // no workspace
            false, // no report
            false, // no force_unlock
            None,  // no output mode
            false, // no progress
            false, // no timing
            0,     // no retry
            true,  // yes (skip prompt)
            false,
            None,
            false,
            None,
            None,
            None,  // subset
            false, // confirm_destructive
            None,  // exclude
            false, // sequential
        )
        .unwrap();
    }

