    #[test]
    fn test_fj285_collect_transitive_deps() {
        let yaml = r#"
version: "1.0"
name: test
machines:
  local:
    hostname: local
    addr: 127.0.0.1
resources:
  a:
    type: file
    machine: local
    path: /tmp/a.txt
    content: "a"
    depends_on: [b]
  b:
    type: file
    machine: local
    path: /tmp/b.txt
    content: "b"
    depends_on: [c]
  c:
    type: file
    machine: local
    path: /tmp/c.txt
    content: "c"
  d:
    type: file
    machine: local
    path: /tmp/d.txt
    content: "d"
"#;
        let config: types::ForjarConfig = serde_yaml_ng::from_str(yaml).unwrap();
        let deps = collect_transitive_deps(&config, "a").unwrap();
        assert!(deps.contains("a"));
        assert!(deps.contains("b"));
        assert!(deps.contains("c"));
        assert!(!deps.contains("d"));
        assert_eq!(deps.len(), 3);
    }

